INSERT INTO `accommodations` (`id`, `name`, `slug`, `type`, `category`, `location`, `destination_id`, `country_id`, `currency`, `price_from`, `price_to`, `short_description`, `full_description`, `featured_image`, `amenities`, `is_active`, `is_featured`, `sort_order`, `created_at`, `updated_at`) VALUES
(1, 'Entebbe Budget Guesthouse', 'entebbe-budget-guesthouse-BnOID', 'Guesthouse', 'budget', 'Entebbe – residential area, short drive from airport', 29, 3, 'USD', '40.00', '70.00', 'Simple, clean guesthouse in Entebbe, ideal for budget-conscious travelers needing a safe and comfortable place before or after their safari.', NULL, 'accommodations/featured/z3zvGCUibRy5OjX6bb3YdJZQq1Skho7S1MYG4NmH.jpg', '[\"En-suite bathrooms\",\"Hot showers\",\"Restaurant\",\"Wi-Fi in public areas\",\"Airport transfers\",\"Secure parking\"]', 1, 0, 10, '2026-02-19 06:32:11', '2026-02-28 13:24:31'),
(2, 'Red Chilli Rest Camp', 'murchison-budget-camp-zCF6G', 'Tented Camp', 'budget', 'Near Murchison Falls National Park gate', 17, 3, 'USD', '45.00', '150.00', 'Nestled in the heart of Murchison Falls National Park at Paraa, Red Chilli Rest Camp is the ultimate base for budget-conscious adventurers. Located just 500 meters from the Nile ferry crossing, it offers unparalleled access to the park\'s premier game-viewing tracks. Whether you’re staying in a cozy banda or camping under the stars, you’ll enjoy a lively atmosphere, a well-stocked bar, and a nightly campfire perfect for sharing safari stories.', NULL, 'accommodations/featured/AS254cn2zTlg46qiofwURMoAQUh7kn0OSt8aPbpV.jpg', '[\"Mosquito nets\",\"Restaurant\",\"Bar\",\"Campfire area\",\"Guided nature walks\"]', 1, 0, 20, '2026-02-19 06:32:12', '2026-03-24 18:08:24'),
(3, 'Enjojo Lodge', 'queen-budget-lodge-EhFla', 'Lodge', 'mid-range', 'Queen Elizabeth National Park - Ishasha sector', 16, 3, 'USD', '150.00', '250.00', 'Tucked away in the lush acacia woodland bordering the southern Ishasha sector of Queen Elizabeth National Park, Enjojo Lodge offers a soulful escape into the Ugandan wilderness. Named after the local word for elephant, this eco-friendly retreat spans 40 hectares of private land where elephants, buffaloes, and colobus monkeys frequently roam. Whether you choose a luxury thatched cottage with an outdoor rock shower, a private safari house, or a quiet campsite, you’ll be perfectly positioned just minutes from the park gate the prime territory for spotting the world-famous tree-climbing lions. After a day on safari, you can unwind at the open-air restaurant, enjoying organic meals harvested from the lodge’s own garden while overlooking the tranquil Akanyanza Lake.', NULL, 'accommodations/featured/CtY99K6ziEnXkI1H97pfk3B7jYwzRCE6ry3XZFuZ.jpg', '[\"Hot showers\",\"24-hour electricity\",\"Restaurant\",\"Bar\",\"Lounge\",\"Secure parking\"]', 1, 0, 30, '2026-02-19 06:32:12', '2026-03-26 15:40:54'),
(4, 'Heritage Safari Lodge', 'bwindi-budget-lodge-dvitR', 'Lodge', 'mid-range', 'Situated just 3 km from the Tangi Gate of Murchison Falls National Park, the lodge sits on the southern bank of the Albert Nile.', 15, 3, 'USD', '70.00', '150.00', 'Heritage Safari Lodge is more than just a place to sleep; it is a tribute to the Acholi heritage of Northern Uganda. The lodge is designed in the style of a traditional Acholi village, featuring stepped-thatch roofs and organic building materials that blend seamlessly into the dry savannah landscape. Each cottage (or Banda) is spaced out to ensure maximum privacy and an authentic \"bush\" feel.', NULL, 'accommodations/featured/NlLH6lmr4y9u4TswN6kAruDqCzRhkwatadNK2rMm.jpg', '[\"Solar power\",\"Restaurant\",\"Bar\",\"Wi-Fi in rooms\",\"Laundry service\"]', 1, 0, 40, '2026-02-19 06:32:12', '2026-03-24 19:13:51'),
(5, 'Mpogo Lodge', 'lake-victoria-view-guesthouse-LEGfI', 'Lodge', 'budget', 'Inside Lake Mburo National Park', 28, 3, 'USD', '100.00', '200.00', 'Gemini said\r\nMpogo Safari Lodge is a peaceful, 16-room hilltop retreat on the outskirts of Lake Mburo National Park that offers affordable mid-range accommodation and a unique history of wildlife visiting its natural salt well', 'Mpogo Safari Lodge is a peaceful and exclusive mid-range facility conveniently perched atop a hill on the outskirts of Lake Mburo National Park in Western Uganda. Originally a humble family farmhouse, the lodge was born from the unique experience of having the park’s wildlife including Zebras, Buffaloes, Antelopes, and the occasional hyena visit its natural salt well daily. This 16-room facility offers high-quality, affordable accommodation that perfectly blends cultural tourism with the natural wonders of the park. With a fully equipped kitchen, traditional thatched huts, and scenic camping grounds, Mpogo Lodge provides travelers with an authentic taste of both the traditional and modern Ugandan safari experience.', 'accommodations/featured/ZBEoe18AByUpZmEGnU7UdshrLHndQSELGbMsamJf.jpg', '[\"En-suite bathrooms\",\"24-hour electricity\",\"Solar power\",\"Mosquito nets\",\"Restaurant\",\"Bar\",\"Lounge\",\"Wi-Fi in public areas\",\"Wi-Fi in rooms\",\"Family rooms\",\"Guided nature walks\",\"Airport transfers\",\"Secure parking\"]', 1, 0, 50, '2026-02-19 06:32:13', '2026-03-31 21:07:50'),
(6, 'Hyena Hill Lodge', 'para-safari-lodge-H9aS3', 'Lodge', 'budget', 'Inside Lake Mburo National Park', 28, 3, 'USD', '110.00', '120.00', 'Hyena Hill Lodge is an eco-friendly hilltop retreat located near the Sanga Gate of Lake Mburo National Park, offering breathtaking panoramic views, comfortable cottages, and a unique blend of Dutch and Ugandan hospitality.', 'Hyena Hill Lodge is a charming, eco-conscious facility situated on the edge of Lake Mburo National Park, providing guests with one of the most spectacular views in Western Uganda. Located near the Sanga Gate, the lodge features artistically designed cottages and family rooms that blend traditional Ugandan materials with modern comfort. Known for its warm atmosphere and personalized service, the lodge is a perfect base for adventure, offering unique activities such as bicycle safaris, guided nature walks, and birdwatching. Whether relaxing on a private balcony overlooking the savanna or enjoying a freshly prepared meal in the open-air restaurant, visitors at Hyena Hill Lodge experience a peaceful and authentic connection to the African wilderness.', 'accommodations/featured/lTZ6CnTbFcKKqGCJJYosGrxwUPMhY2p1pL6G7fbR.jpg', '[\"En-suite bathrooms\",\"Hot showers\",\"Solar power\",\"Mosquito nets\",\"Restaurant\",\"Bar\",\"Lounge\",\"Wi-Fi in public areas\",\"Family rooms\",\"Guided nature walks\"]', 1, 0, 60, '2026-02-19 06:32:13', '2026-03-31 21:32:51'),
(7, 'Apoka Safari Lodge', 'kasese-plains-lodge-9FzGN', 'Lodge', 'budget', 'Located inside Kidepo Valley  National park', 27, 3, 'USD', '150.00', '220.00', 'Apoka Safari Lodge is built around a picturesque rocky outcrop overlooking the Narus Valley in the southwestern sector of Kidepo Valley National Park', 'poka Safari Lodge is built around a picturesque rocky outcrop overlooking the Narus Valley in the southwestern sector of Kidepo Valley National Park – Uganda’s most remote park. Kidepo presents an amazing wildlife experience with pristine wilderness in  abundance:  Lions, leopards, cheetahs (Kidepo is the only park in Uganda with cheetahs),elephants, giraffes, zebras, ostriches, and possibly Africa’s largest herds of buffalos…as well as rarities such as the tantalus monkey.\r\n\r\nThe vast golden green plains are punctuated with craggy, rocky outcrops, revealing an even bigger sky at night. Under this canopy of impossibly bright stars, this is where we are reminded that the Earth is round.  Apoka Safari Lodge, relaxed and comfortable, is the only full-service lodge in the national park.  Rooms have canvas walls and thatched roofs, and feature massive outdoor rock tubs for day-time cooling soaks or night-time bubble baths. The main lodge sits up on stilts and offers incredible far-reaching views over the plains – and the wildlife that wanders past. The main star of Apoka (beyond the outrageously beautiful scenery) is the large swimming pool, carved out of the rock face that makes you want to leap in, arms in the air, shouting ‘Yahooooo!’.', 'accommodations/featured/rO0M0bN8a6m37H3baV3qCQhe2X7jia6lK6wULFYs.jpg', '[\"En-suite bathrooms\",\"Hot showers\",\"Mosquito nets\",\"Restaurant\",\"Bar\",\"Wi-Fi in public areas\",\"Swimming pool\",\"Family rooms\",\"Secure parking\"]', 0, 0, 70, '2026-02-19 06:32:13', '2026-04-02 15:41:19'),
(8, 'Zebra safari lodge', 'bwindi-forest-camp-9qJMr', 'Lodge', 'mid-range', 'Inside Kidepo Valley National aprk', 27, 3, 'USD', '118.00', '212.00', 'Zebra Safari Lodge-Kidepo is located just a stone’s throw away from the famous Kalokudo Gate in Kidepo Valley National Park, Karamoja Sub-region, North Eastern part of Uganda.', 'Zebra Safari Lodge-Kidepo boasts of five luxurious King Size Cottages, set out on raised ground. Each of the spacious cottages has a private verandah offering splendid views of the mighty unending savannah vegetation, together with a cool breeze of unpolluted air. Comfortably furnished with 1 King Size Bed, all our cottages have an ensuite bathroom with 24 hours hot showers, running water for hand-basins and a flushing toilet.', 'accommodations/featured/8FiXpx9blhzwGYvPne4UPDkqVhp39lZ0H0yTCKwq.jpg', '[\"En-suite bathrooms\",\"Hot showers\",\"Solar power\",\"Mosquito nets\",\"Restaurant\",\"Bar\",\"Laundry service\",\"Campfire area\",\"Guided nature walks\"]', 0, 0, 80, '2026-02-19 06:32:14', '2026-04-02 16:22:13'),
(9, 'Bakiga Lodge', 'entebbe-lakefront-boutique-hotel-IpYdT', 'Lodge', 'mid-range', 'Bwindi Impenetrable Forest National Park', 15, 3, 'USD', '160.00', '250.00', 'Built overlooking a beautiful valley, Bakiga Lodge is a wonderful accommodation for visitors looking for a real african experience with amazing views of Bwindi Impenetrable Forest. We are a high quality african eco lodge, situated in the Ruhija sector of Bwindi national park, just a 10 minute drive from the Ruhija Gorilla Tracking meeting point. Please note the terrain of the lodge is quite steep.', NULL, 'accommodations/featured/HvQThzrFiUMkzqCfT1O3wws0VJwB66G6v8U4ebt0.jpg', '[\"En-suite bathrooms\",\"Solar power\",\"Air conditioning\",\"Restaurant\",\"Bar\",\"Wi-Fi in rooms\",\"Spa \\/ massage services\",\"Family rooms\",\"Guided nature walks\",\"Airport transfers\"]', 1, 1, 90, '2026-02-19 06:32:14', '2026-04-08 01:14:48'),
(10, 'Murchison Luxury Safari Lodge', 'murchison-luxury-safari-lodge-foLfH', 'Lodge', 'high-end', 'Inside Murchison Falls National Park, exclusive riverfront', 17, 3, 'USD', '350.00', '550.00', 'High-end safari lodge with spacious suites, private decks, and exceptional service on a quiet stretch of the Nile in Murchison Falls National Park.', NULL, 'accommodations/featured/murchison-luxury-lodge.jpg', '[\"En-suite bathrooms\",\"Air conditioning\",\"Restaurant\",\"Bar\",\"Lounge\",\"Wi-Fi in rooms\",\"Swimming pool\",\"Spa \\/ massage services\",\"Laundry service\",\"Guided nature walks\"]', 0, 1, 100, '2026-02-19 06:32:15', '2026-03-31 21:56:45'),
(11, 'Queen Luxury Hills Lodge', 'queen-luxury-hills-lodge-mVUzp', 'Lodge', 'high-end', 'Hills above Queen Elizabeth National Park', 16, 3, 'USD', '320.00', '480.00', 'Luxurious lodge set on a hillside with sweeping views over Queen Elizabeth National Park, offering elegant suites, fine dining, and a tranquil pool area.', NULL, 'accommodations/featured/queen-luxury-hills-lodge.jpg', '[\"En-suite bathrooms\",\"Air conditioning\",\"Restaurant\",\"Bar\",\"Lounge\",\"Wi-Fi in rooms\",\"Swimming pool\",\"Spa \\/ massage services\",\"Honeymoon suite\"]', 0, 1, 110, '2026-02-19 06:32:16', '2026-03-31 21:56:26'),
(12, 'Bwindi Luxury Forest Lodge', 'bwindi-luxury-forest-lodge-CJo6V', 'Lodge', 'high-end', 'Exclusive forest setting near Bwindi gorilla tracking trails', 15, 3, 'USD', '400.00', '650.00', 'High-end forest lodge offering spacious cottages, fireplaces, gourmet cuisine, and personalized service just a short drive from Bwindi’s gorilla tracking start points.', NULL, 'accommodations/featured/bwindi-luxury-forest-lodge.jpg', '[\"En-suite bathrooms\",\"Restaurant\",\"Bar\",\"Wi-Fi in public areas\",\"Spa \\/ massage services\",\"Laundry service\",\"Honeymoon suite\",\"Guided nature walks\"]', 0, 1, 120, '2026-02-19 06:32:17', '2026-03-31 21:55:02'),
(13, 'Pakuba safari Lodge', 'pakuba-safari-lodge-RoSec', 'Lodge', 'high-end', 'Murchison Falls National Park', 17, 3, 'USD', '180.00', '250.00', 'For travelers seeking comfort without the luxury price tag, Pakuba Safari Lodge provides exceptional mid-range value inside Uganda’s largest national park. Guests enjoy spacious en-suite rooms with 24-hour service, free Wi-Fi in main areas, and a picturesque pool deck perfect for sunset cocktails. Its location near the Tangi Gate and Pakuba Airstrip makes it one of the most accessible and strategically placed lodges for seeing the \"Big Five\".', 'Pakuba Safari Lodge is a premier mid-range retreat ideally situated on the eastern bank of the Albert Nile in the northern sector of Murchison Falls National Park, a location famous for its high concentration of wildlife. The lodge features over 40 spacious, air-conditioned rooms with private verandas that offer stunning views of the river and frequently visited grounds where elephants, giraffes, and hippos roam freely. Guests can enjoy modern comforts including an outdoor swimming pool, an on-site restaurant serving local and international cuisine, and 24-hour solar power. Perfectly positioned for immediate access to the park\'s best game tracks and the Pakuba Airstrip, it serves as an exceptional base for early morning safaris, Nile boat cruises, and tracking the \"Big Five\" in Uganda\'s most iconic wilderness.', 'accommodations/featured/q2L8TBd7XfrDi5H4C5Zm3r3NITY0sK5d6vJHgbsr.jpg', '[\"24-hour electricity\",\"Air conditioning\",\"Restaurant\",\"Bar\",\"Swimming pool\",\"Laundry service\",\"Campfire area\"]', 1, 1, 1, '2026-02-19 07:57:04', '2026-02-19 10:33:24'),
(14, 'Twiga safari lodge', 'twiga-safari-lodge-yCTrZ', 'Lodge', 'mid-range', 'Murchison Falls National Park', 17, 4, 'USD', '200.00', '300.00', 'Twiga Safari Lodge is a mid-range, boutique lodge situated on the southern bank of the River Nile in the Mubaako-Paraa area of Murchison Falls National Park, Uganda. It is known for its unique \"glamping\" style, featuring eight elevated cottages that fuse traditional African thatched roofs with canvas safari tents', NULL, 'accommodations/featured/iEtqBjocdJV1tVKaI3ba1Hplzzp2DUYu9ZBugghv.jpg', '[\"Mosquito nets\",\"Air conditioning\",\"Restaurant\",\"Wi-Fi in rooms\",\"Room service\",\"Honeymoon suite\"]', 1, 0, 5, '2026-03-04 10:12:11', '2026-03-04 10:22:15'),
(15, 'Kibale  Tourist Lodge', 'kibale-tourist-lodge-GetXq', 'Lodge', 'budget', 'Bigodi Village along the Fort Portal-Kamwenge Road, just 10 minutes from Kibale National Park\'s chimpanzee trekking', 19, 3, 'USD', '100.00', '250.00', 'Kibale Tourist Safari Lodge is a serene eco-lodge on Bigodi Swamp\'s shores, providing executive cottages and family options near Kibale National Park for chimp trekking. Enjoy unrivaled comfort, a restaurant/bar, and warm hospitality amid Uganda\'s pristine wilderness.', NULL, 'accommodations/featured/ZpjfTFLsfOtm98EZdTUtMK6Rs08Xhc01ZNMfisy5.jpg', '[\"Restaurant\",\"Campfire area\",\"Guided nature walks\"]', 1, 0, 0, '2026-03-08 22:01:17', '2026-03-24 17:30:06'),
(16, 'Turaco treetops lodge', 'turaco-treetops-lodge-VBPNk', 'Lodge', 'mid-range', 'Turaco Treetops is located on a 5.2-hectare private forest bordering Kibale National Park in Western Uganda, just a 15-minute drive from the Kanyanchu chimpanzee trekking start point.', 19, 3, 'USD', '275.00', '490.00', 'Turaco Treetops is a semi-luxury forest lodge at the edge of Kibale National Park, offering stylish cottages and a solar-heated pool for the ultimate chimpanzee trekking home base.', 'uraco Treetops offers a premier semi-luxury escape nestled on the lush edge of Kibale Forest National Park, Uganda’s primate capital. Designed to blend modern comfort with an authentic \"African forest\" feel, the lodge features secluded luxury cottages and spacious rooms, all boasting private balconies with stunning views of the canopy or the distant Rwenzori Mountains. As an ideal base for chimpanzee trekking, it sits just minutes from the park headquarters, allowing guests to transition seamlessly from a morning of wildlife encounters to an afternoon of relaxation by the solar-heated pool. With its commitment to sustainability, family-friendly amenities, and a peaceful atmosphere frequenting with Great Blue Turacos and monkeys, it is the perfect sanctuary for travelers seeking both adventure and tranquility in the heart of nature.', 'accommodations/featured/huWnty5iitxyX1cik06w3WdFjvlphYYAayZYVVuj.jpg', '[\"Hot showers\",\"Mosquito nets\",\"Air conditioning\",\"Restaurant\",\"Bar\",\"Lounge\",\"Swimming pool\",\"Family rooms\"]', 1, 0, 0, '2026-03-27 13:06:14', '2026-03-27 13:06:14');

