(21, 2, 'Rwenzori Trekking', 'rwenzori-trekking', NULL, NULL, NULL, 'Multi-day trek in the mystical Mountains of the Moon.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'USD', NULL, NULL, NULL, 0, 1, 7, '2026-02-07 14:36:56', '2026-02-07 14:36:56', 21),
