INSERT INTO `activity_categories` (`id`, `name`, `slug`, `description`, `icon`, `is_active`, `sort_order`, `created_at`, `updated_at`) VALUES
(1, 'Wildlife Safari', 'wildlife-safari', 'Experience thrilling wildlife encounters and game drives', 'fas fa-binoculars', 1, 1, '2026-02-07 14:36:54', '2026-02-09 03:21:40'),
(2, 'Adventure Sports', 'adventure-sports', 'Adrenaline-pumping outdoor adventures', 'fas fa-hiking', 1, 2, '2026-02-07 14:36:54', '2026-02-07 14:36:54'),
(3, 'Cultural Experience', 'cultural-experience', 'Immerse in local traditions and communities', 'fas fa-users', 1, 3, '2026-02-07 14:36:54', '2026-02-07 14:36:54'),
(4, 'Water Activities', 'water-activities', 'Beach, diving, and water-based adventures', 'fas fa-water', 1, 4, '2026-02-07 14:36:54', '2026-02-07 14:36:54'),
(5, 'Nature & Scenery', 'nature-scenery', 'Explore breathtaking landscapes and natural wonders', 'fas fa-mountain', 1, 5, '2026-02-07 14:36:54', '2026-02-07 14:36:54'),
(6, 'Water Sports & Activities', 'water-sports-activities', 'Experience thrilling water-based adventures across East Africa\'s magnificent lakes, rivers, and coastlines. From white-water rafting on the mighty Nile to kayaking on serene lakes, stand-up paddleboarding, sport fishing, and boat safaris. Whether you\'re seeking adrenaline-pumping rapids or peaceful sunset cruises, our water activities offer unforgettable aquatic experiences suitable for all skill levels.', 'fas fa-water', 1, 5, '2026-02-09 03:34:34', '2026-02-09 04:10:39'),
(7, 'Mountain & Hiking Adventures', 'mountain-hiking-adventures', 'Conquer Africa\'s legendary peaks and explore stunning mountain landscapes. Trek through the Rwenzori Mountains (Mountains of the Moon), climb Mount Kilimanjaro, hike volcanic peaks in the Virunga ranges, or enjoy scenic nature walks through highland forests. Our mountain adventures cater to everyone from casual day hikers to serious mountaineers seeking multi-day expeditions at high altitude.', 'fas fa-mountain', 1, 6, '2026-02-09 04:12:38', '2026-02-09 04:12:38');

