INSERT INTO `tours` (`id`, `title`, `slug`, `status`, `category`, `destinations`, `type`, `description`, `included`, `excluded`, `meta_keywords`, `meta_description`, `meta_title`, `featured_image`, `created_at`, `updated_at`) VALUES
(1, '3-Day Bwindi Gorilla Trekking Safari with Lake Bunyonyi Retreat', 'uganda-gorilla-trekking-bwindi-bunyonyi-entebbe', 'published', 'Budget', 'Uganda(Bwind Impenatrable Forest National Park, Lake Bunyonyi)', 'Gorilla Trekking', 'Experience the adventure of a lifetime with our Uganda Gorilla Trekking Safari! Arrive in Entebbe a night before your safari or take advantage of an early morning landing to maximize your time in Uganda. Your dedicated, professional tour driver/guide will greet you and set off for the renowned Bwindi Impenetrable National Park home to the majestic mountain gorillas.\r\n\r\nEmbark on an unforgettable gorilla trekking expedition through the lush forests of Bwindi, where you\'ll have the rare opportunity to observe mountain gorillas in their natural habitat. After a rewarding and strenuous day trekking, unwind in ultimate comfort and serenity at Lake Bunyonyi, Uganda’s picturesque “Lake of Little Birds.” Enjoy scenic views, relaxation, and the tranquil atmosphere that makes this destination a favorite retreat for safari travelers.\r\n\r\nOn your third day, take a leisurely return journey to Entebbe, reflecting on your close encounters with wildlife and breathtaking landscapes. This carefully curated safari combines the thrill of gorilla trekking with the peacefulness of Lake Bunyonyi, ensuring a truly memorable Uganda adventure from start to finish.', 'Ground Transportation\r\n\r\nGorilla permits (800 Per person)\r\n\r\nActivities unless labeled option\r\n\r\nEnglish speaking Guide/ Driver\r\n\r\nAccomadation (Budget)\r\n\r\nDrinking water', 'Uganda visa\r\n\r\nCovid 19 test\r\n\r\ninternational flights\r\n\r\nActivities suggested as optional', 'budget Uganda safari, 3 days gorilla Trekking  safari in Uganda', 'Embark on a once-in-a-lifetime 3-day Uganda gorilla trekking safari. Witness mountain gorillas in Bwindi Impenetrable National Park, unwind at the picturesque Lake Bunyonyi, and savor adventure and wildlife experiences before returning to Entebbe.', 'Uganda Gorilla Trekking Adventure: Bwindi, Lake Bunyonyi & Entebbe (3 Days)', 'tours/featured_images/kaKsvLmGIbIO5mt17mEMC2Eld9NkcqILYzUUtjw9.jpg', '2026-01-31 11:14:37', '2026-04-08 23:11:15'),
(4, '7-Day Uganda Adventure Safari: Gorillas, Wildlife & Cultural Experience', '7-day-uganda-adventure-safari-gorillas-wildlife-culture', 'published', 'Budget', 'Uganda(Bwind Impenatrable Forest National Park, Lake Bunyonyi)', 'Adventure and Gorilla Trekking', 'Embark on the ultimate 7-day Uganda adventure safari, designed for thrill-seekers and wildlife enthusiasts craving an authentic African experience. This comprehensive safari combines the best of Uganda\'s diverse landscapes, incredible wildlife, and rich cultural heritage.\r\n\r\nYour adventure begins with mountain gorilla trekking in the legendary Bwindi Impenetrable National Park, where you\'ll come face-to-face with these magnificent creatures in their natural habitat. Continue to Queen Elizabeth National Park for classic Big Five game drives, boat safaris along the Kazinga Channel, and unforgettable wildlife encounters.\r\n\r\nExperience Uganda\'s cultural diversity through authentic village visits, traditional performances, and interactions with local communities. Witness the dramatic landscapes of the Rwenzori Mountains, explore crater lakes, and enjoy world-class birdwatching opportunities throughout your journey.\r\n\r\nThis carefully crafted itinerary ensures maximum wildlife viewing, cultural immersion, and adventure while maintaining comfort and safety standards expected by international travelers. From tracking endangered mountain gorillas to spotting lions, elephants, and hippos, every day brings new discoveries in the \"Pearl of Africa.\"', 'Accommodation & Meals:\r\n\r\n6 nights accommodation (mid-range lodges and safari camps)\r\nAll meals as specified in the itinerary (6 breakfasts, 6 lunches, 6 dinners)\r\nBottled water during safari activities\r\nTransportation:\r\n\r\nAirport transfers (arrival and departure)\r\nPrivate 4WD safari vehicle with pop-up roof for game viewing\r\nProfessional English-speaking driver-guide throughout the safari\r\nFuel for the entire safari\r\nPark Fees & Permits:\r\n\r\nMountain gorilla trekking permit (USD 700 value)\r\nAll national park entrance fees\r\nKazinga Channel boat safari\r\nWalking safari in Lake Mburo National Park\r\nActivities & Experiences:\r\n\r\nKampala city tour (depending on arrival time)\r\nBatwa cultural community visit\r\nGame drives in Queen Elizabeth and Lake Mburo National Parks\r\nProfessional ranger guide for gorilla trekking', 'International flights to/from Uganda\r\n\r\nUganda entry visa (USD 50 for most nationalities)\r\n\r\nTravel insurance (highly recommended)\r\n\r\nAlcoholic beverages and premium drinks\r\n\r\nPersonal shopping and souvenirs\r\nTips and gratuities for guides, drivers, and lodge staff\r\nLaundry services\r\nTelephone calls and internet charges', '7 days Uganda safari, chimpanzee trekking Kibale Forest, Uganda chimpanze trekking safari', 'Experience a 7-day Uganda safari with gorilla trekking in Bwindi, Big Five game drives in Queen Elizabeth, cultural tours, and unforgettable wildlife adventures', 'Ultimate 7-Day Uganda Adventure Safari: Gorillas, Wildlife & Cultural Experience', 'tours/featured_images/NogB0Xjf8mc3NH6spTWtaR8dvpAjL7KyfMwEfHFe.jpg', '2026-02-01 08:16:01', '2026-04-08 23:10:24'),
(7, '14 Days Uganda Midrange Safari – Gorilla, Chimpanzee & Wildlife Experience', '14-Day Uganda Midrange Safari – Gorillas,', 'published', 'Middle Range', 'Uganda(Bwind Impenatrable Forest National Park, Lake Bunyonyi)', 'Adventure and Gorilla Trekking', 'Experience the breathtaking soul of the \"Pearl of Africa\" with a 14-day immersive safari designed to balance raw adventure with refined, midrange comfort. This isn\'t just a tour; it’s a deep dive into Uganda’s most iconic landscapes, from the mist-shrouded peaks of gorilla trekking to the golden savannahs of classic game drives. You will travel at a thoughtful pace in a private 4x4 vehicle, led by an expert guide who brings the wilderness to life through local stories and wildlife mastery. Each evening, retreat to handpicked boutique lodges and tented camps that offer the perfect blend of scenic views, hot showers, and warm Ugandan hospitality without the luxury price tag. Whether you are tracking chimpanzees through ancient forests, drifting along the Nile on a boat safari, or sharing a laugh during a cultural encounter, this journey is crafted for those who want to see the world deeply and personally. Escape the rush and truly feel the rhythm of the wild the result is an authentic, soul-stirring expedition that leaves you refreshed and inspired. This is Uganda, experienced at its very best.', 'Gorilla trekking permit (1 per person)\r\n\r\nChimpanzee tracking permit (1 per person)\r\n\r\nAll national park entrance and conservation fees\r\n\r\nAll scheduled game drives and park activities in the itinerary\r\n\r\nBoat safaris and launch cruises mentioned in the program\r\n\r\nRhino tracking experience\r\n\r\nWalking safari with armed ranger where scheduled\r\n\r\nPrivate 4x4 safari vehicle with pop-up roof for game viewing\r\n\r\nProfessional English-speaking safari guide/driver (full trip)\r\n\r\nAll ground transportation and fuel for the entire itinerary\r\n\r\nAirport pickup and drop-off\r\n\r\nAccommodation in midrange lodges and tented camps (private rooms)\r\n\r\nMeals as per itinerary (usually full board while on safari)\r\n\r\nBottled drinking water in the vehicle during drives\r\n\r\nRanger fees and activity guide fees\r\n\r\nAll government taxes and service charges\r\n\r\nEn-route stop at the Equator for photos', 'International and domestic flights\r\n\r\nUganda visa fees\r\n\r\nTravel insurance (medical + evacuation recommended)\r\n\r\nOptional activities not listed in the itinerary\r\n\r\nExtra nights before/after the safari (unless requested)\r\n\r\nAlcoholic drinks and premium beverages at lodges\r\n\r\nPersonal expenses (laundry, souvenirs, tips, phone calls)\r\n\r\nTips and gratuities for guide, lodge staff, and rangers\r\n\r\nPorter fees during gorilla and chimp trekking (optional but recommended)\r\n\r\nAny activity added after itinerary confirmation\r\n\r\nVaccinations and personal medical costs\r\n\r\nSnacks and drinks not provided by lodges', 'Uganda safari tours, 14-days uganda safari, mid-range uganda safaris', 'Explore Uganda with in 14 days of unrushed midrange safari, with calm atmosphere', '14-Day Uganda Midrange Safari – Gorillas, Chimps, Big Five & Scenic Parks', 'tours/featured_images/a68ncPkmwzKxcXk5szLWLnwQCOPgkDl4HrrJgj7d.jpg', '2026-02-19 05:31:17', '2026-04-09 00:46:25'),
(8, '12 days :Rhinos, Big Game, and Primates safari', 'hinos-big-game-and-primates', 'published', 'Budget', 'Ziwa, Queen Elizabeth National park, Murchison Fall Np, Kibale Forest NP, lake Mburo', 'wildlife and Chimpanzee tracking', 'Experience the absolute best of the \"Pearl of Africa\" on this comprehensive 12-day journey designed for the savvy traveler. This safari is the perfect introduction to Uganda’s diverse landscapes from the thundering Murchison Falls on the Nile to the ancient, misty canopy of Kibale Forest.\r\n\r\nYou will track wild Rhinos on foot, search for Lions and Leopards across the golden savannas of Queen Elizabeth National Park, and come face-to-face with our closest relatives during an unforgettable Chimpanzee trek. Designed with a focus on value without sacrificing the experience, this itinerary balances iconic wildlife encounters with authentic cultural moments and the peaceful beauty of Lake Mburo.', 'Transport: A customized 4x4 Safari Van with a pop-up roof for 360-degree wildlife viewing and photography.\r\n\r\nDriver-Guide: Services of a professional, English-speaking Ugandan driver-guide (expert in wildlife spotting and local history).\r\n\r\nAccommodation: 11 nights in hand-picked budget lodges, tented camps, or guesthouses.\r\n\r\nMeals: Full Board (Breakfast, Lunch, and Dinner) .\r\n\r\nPermits: Includes one Chimpanzee Tracking Permit for Kibale Forest and Rhino Tracking Fees for Ziwa.\r\n\r\nPark Fees: All National Park entrance fees for Murchison Falls, Kibale, Queen Elizabeth, and Lake Mburo.\r\n\r\nActivities: All scheduled game drives, boat cruises on the Victoria Nile and Kazinga Channel, and the Bigodi Wetland nature walk.\r\n\r\nWater: Complimentary bottled drinking water provided in the vehicle during all transfers and game drives.', 'Flights: International airfare to/from Entebbe.\r\n\r\nVisa: Uganda Tourist Visa (standard fee is $50, payable online).\r\n\r\nTravel Insurance: Comprehensive medical and trip cancellation insurance (highly recommended).\r\n\r\nDrinks: Soft drinks, sodas, and alcoholic beverages at the lodges.\r\n\r\nTips: Gratuities for your driver-guide (suggested $10–$15 per day) and lodge staff.\r\n\r\nPersonal Items: Laundry services, phone data/SIM cards, and souvenirs.\r\n\r\nOptional Activities: Any activities marked as \"optional\" in the itinerary (e.g., Night game drives or Hot Air Ballooning).', 'Uganda tours and safaris, family safari Uganda itinerary, Uganda cheap safari package, Chimpanze trekking safari in uganda', 'Explore Murchison Falls, Kibale & Queen Elizabeth on our 12-day budget Uganda safari. Includes rhino tracking, chimp trekking & savanna game drives. Book for 2026!', '12-Day Best of Uganda Safari 2026 | Wildlife & Primate Tour', 'tours/featured_images/OZvbZNfWzNxn5uDO7URGq35iKE9kmHTUI2Ykvma8.jpg', '2026-03-28 20:38:41', '2026-04-08 00:14:10'),
(9, '15-Day \"Primate & Pearl\" Mid-Range Discovery', '15-day-primate-pearl-mid-range-discovery', 'published', 'Middle Range', 'Ziwa, Queen Elizabeth National park, Murchison Fall Np, Bwindi impenetrable, lake Bunyonyi,Kibale Forest NP, lake Mburo', 'Adventure and Gorilla Trekking', 'Designed for the discerning traveler, this 15-day expedition offers a deep dive into Uganda’s soul at a relaxed, \"slow-travel\" pace. Moving beyond the basics, this journey balances high-adrenaline encounters like Mountain Gorilla trekking and Chimpanzee tracking with tranquil afternoons on the shores of Lake Bunyonyi. We have carefully curated this itinerary to ensure you aren\'t just passing through landscapes, but living in them, with a dedicated 4x4 Safari Land Cruiser and stays in Uganda’s most charming mid-tier retreats.', 'Superior Mid-Range Accommodations: 14 nights in hand-picked, middle-class boutique lodges and tented camps. Each property is selected for its unique character, en-suite facilities, stunning natural views, and high standards of hospitality.\r\n\r\nPrivate 4x4 Safari Land Cruiser: Travel in comfort and style with a legendary 4x4 Land Cruiser, featuring a pop-up roof for 360° photography and guaranteed window seating.\r\n\r\n Driver-Guide: Services of a highly experienced, silver-level professional guide with specialist knowledge in ornithology and primate behavior.\r\n\r\nAll-Inclusive Primate Permits: Includes one (1) Mountain Gorilla Trekking Permit ($800) and one (1) Chimpanzee Tracking Permit ($250).\r\n\r\nPark & Activity Fees: All entrance fees for Murchison Falls, Queen Elizabeth, and Lake Mburo, plus boat cruises on the Nile and Kazinga Channel.\r\n\r\nFull Board Dining: All gourmet meals (Breakfast, Lunch, Dinner) included from arrival to departure.', 'Flights: International airfare to Entebbe.\r\n\r\nVisas: Uganda E-Visa ($50).\r\n\r\nPorter Fees: Optional porters for Gorilla trekking (highly recommended, approx. $15–$20).\r\n\r\nTips: Gratuities for your dedicated driver-guide and lodge staff.\r\n\r\nInsurance: Mandatory comprehensive travel and medical insurance', 'Uganda safari packages, Uganda gorilla trekking safari, unrushed uganda safari packages', 'Experience Uganda’s Big Five and Mountain Gorillas on a 15-day non-rushed safari. Stay in hand-picked middle-class lodges with expert guides. Book your 2026 adventure!', '15-Day Uganda Gorilla & Wildlife Safari | Mid-Range Boutique Tour 2026', 'tours/featured_images/tVTILWlIW1MWFu6BNcZwc7kZyBFNgnO8oDU6Zr7i.jpg', '2026-03-28 21:24:48', '2026-04-09 00:44:02'),
(10, '10-Day Mid-Range Uganda  Safari', '10-Day-Mid-Range-Uganda-safari', 'published', 'Middle Range', 'Entebbe, murchison, Queen Elizabeth Np, Bwind impenetrable,lake Bunyonyi, Lake Mburo', 'Adventure and Gorilla Trekking', 'Uganda, the “Pearl of Africa” named by Winston Churchill, offers one of the most diverse and rewarding safari experiences on the continent. This 10-day mid-range journey takes you from tracking rhinos at Ziwa Rhino Sanctuary to witnessing the dramatic Nile surge at Murchison Falls National Park, exploring wildlife-rich plains in Queen Elizabeth National Park, and culminating in unforgettable gorilla trekking in Bwindi Impenetrable National Park.\r\n\r\nThe adventure ends with relaxation at Lake Bunyonyi and a final safari in Lake Mburo National Park. With private transport, expert guiding, and comfortable mid-range lodges throughout, this is Uganda at its finest wild, intimate, and truly unforgettable.', 'Airport transfers  \r\nAll accommodation - 9 nights in comfortable mid-range lodges & camps\r\nAll meals - full board throughout (breakfast, lunch & dinner)\r\nPrivate safari vehicle- 4WD pop-up roof vehicle \r\nProfessional English-speaking guide — throughout the entire safari\r\n1 Gorilla trekking permit -Bwindi Impenetrable National Park p/p\r\nRhino trekking - Ziwa Rhino Sanctuary fees & guided walk\r\nAll park entrance fees - Murchison Falls, Queen Elizabeth, Bwindi, Lake Mburo\r\nNile boat cruise- to Murchison Falls\r\nKazinga Channel boat cruise - Queen Elizabeth National Park\r\nAll game drives -as per the itinerary\r\n\r\nDrinking water', 'International flights- to/from Entebbe International Airport\r\nUganda tourist visa- currently USD 50 per person (apply online before travel)\r\nTravel insurance- strongly recommended; must cover medical evacuation\r\nYellow fever vaccination- mandatory for entry into Uganda\r\nPersonal drinks & alcohol- sodas, juices, beers, wines at lodges\r\nTips & gratuities -for guides, lodge staff & rangers (recommended)\r\nOptional activities- e.g. Batwa cultural experience, horseback safari, sport fishing\r\nLaundry services- available at most lodges at own cost\r\nPersonal shopping & souvenirs\r\nPhone calls & internet- WiFi available at most lodges but not guaranteed\r\nMedical expenses- including malaria prophylaxis before travel\r\nAny items of personal nature- not listed above', '10 days Uganda safari, family safari Uganda itinerary, Mid-range Uganda safari', 'Explore Uganda on a 10-day safari: gorilla trekking, Murchison Falls, Queen Elizabeth NP, Lake Bunyonyi & Big Five wildlife with expert guides.', '10-Day Uganda Safari – Gorillas, Wildlife $boat cruises', 'tours/featured_images/nvH8ig1GEeJ1s7QemGZaCKCcz00PrXk4uCmbk03f.jpg', '2026-04-06 23:53:52', '2026-04-08 00:04:56');

