INSERT INTO `tour_itinerary` (`id`, `tour_id`, `day_number`, `activity`, `day_title`, `accommodation`, `accommodation_id`, `meals`, `content_blocks`, `cover_media_id`, `cover_caption`, `updated_by`, `created_at`, `updated_at`) VALUES
(4, 4, 1, 'Upon arrival at Entebbe International Airport, you\'ll be warmly welcomed by our professional driver-guide who will assist with airport formalities and provide a brief safari orientation. Depending on your arrival time, you\'ll be transferred to your comfortable hotel in Kampala for check-in and rest.\r\n\r\nFor early arrivals: After settling in and freshening up, enjoy an optional Kampala city tour including visits to the Kasubi Royal Tombs (UNESCO World Heritage Site), local craft markets, and cultural sites. Experience authentic Ugandan cuisine at a traditional restaurant.\r\n\r\nFor late arrivals: Check into your hotel, enjoy dinner, and rest to prepare for your adventure safari ahead.\r\n\r\nEvening briefing about your upcoming safari itinerary, equipment check, and time to relax after your international journey.', 'Arrival in Entebbe - Transfer to Kampala', 'booked hotel', NULL, 'Lunch (for early arrivals), Dinner', '[{\"id\":\"blk-91869e62-9976-4963-b84d-8be1a7b7997a\",\"type\":\"text\",\"text\":\"Upon arrival at Entebbe International Airport, you\'ll be warmly welcomed by our professional driver-guide who will assist with airport formalities and provide a brief safari orientation. Depending on your arrival time, you\'ll be transferred to your comfortable hotel in Kampala for check-in and rest.\\r\\n\\r\\nFor early arrivals: After settling in and freshening up, enjoy an optional Kampala city tour including visits to the Kasubi Royal Tombs (UNESCO World Heritage Site), local craft markets, and cultural sites. Experience authentic Ugandan cuisine at a traditional restaurant.\\r\\n\\r\\nFor late arrivals: Check into your hotel, enjoy dinner, and rest to prepare for your adventure safari ahead.\\r\\n\\r\\nEvening briefing about your upcoming safari itinerary, equipment check, and time to relax after your international journey.\"}]', NULL, NULL, NULL, '2026-02-01 08:16:01', '2026-02-13 06:03:49'),
(5, 4, 2, 'After an early breakfast, begin your scenic journey southwest towards Bwindi Impenetrable National Park, home to nearly half of the world\'s remaining mountain gorillas. The drive takes you through Uganda\'s beautiful countryside, rolling hills, terraced farmlands, and traditional villages.\r\n\r\nStop at the Uganda Equator for photos and souvenir shopping, then continue through Mbarara town for lunch and a brief rest. As you approach Bwindi, marvel at the dramatic landscape changes and the misty forests that give this UNESCO World Heritage Site its mystical atmosphere.\r\n\r\nArrive at your lodge in the late afternoon, check in, and enjoy spectacular views of the impenetrable forest. Evening briefing about tomorrow\'s gorilla trekking adventure, including what to expect, packing essentials, and safety guidelines.', 'Kampala to Bwindi Impenetrable National Park', 'booked hotel', NULL, 'Breakfast, Lunch, Dinner', '[{\"id\":\"blk-be8c675f-031b-4f21-b0aa-d53c3c4a5914\",\"type\":\"text\",\"text\":\"After an early breakfast, begin your scenic journey southwest towards Bwindi Impenetrable National Park, home to nearly half of the world\'s remaining mountain gorillas. The drive takes you through Uganda\'s beautiful countryside, rolling hills, terraced farmlands, and traditional villages.\\r\\n\\r\\nStop at the Uganda Equator for photos and souvenir shopping, then continue through Mbarara town for lunch and a brief rest. As you approach Bwindi, marvel at the dramatic landscape changes and the misty forests that give this UNESCO World Heritage Site its mystical atmosphere.\\r\\n\\r\\nArrive at your lodge in the late afternoon, check in, and enjoy spectacular views of the impenetrable forest. Evening briefing about tomorrow\'s gorilla trekking adventure, including what to expect, packing essentials, and safety guidelines.\"}]', NULL, NULL, NULL, '2026-02-01 08:16:01', '2026-02-13 06:03:49'),
(6, 4, 3, 'Today is the highlight of your safari! After an early breakfast, head to the park headquarters for registration and a comprehensive briefing by Uganda Wildlife Authority rangers. Learn about gorilla behavior, trekking etiquette, and safety protocols before being assigned to your gorilla family and ranger guides.\r\n\r\nBegin your trek into the dense, misty forests of Bwindi in search of one of the habituated mountain gorilla families. The trek can take anywhere from 2-8 hours depending on the gorillas\' location, traversing steep terrain and thick vegetation. The moment you encounter these gentle giants in their natural habitat will be unforgettable - you\'ll have one precious hour to observe and photograph them.\r\n\r\nAfter the trek, return to your lodge for lunch and rest. In the afternoon, visit the local Batwa (Pygmy) community for an authentic cultural experience. Learn about their traditional forest lifestyle, enjoy cultural performances, and support community-based tourism initiatives.', 'Gorilla Trekking in Bwindi - Cultural Experience', 'Booked hotel', NULL, 'Breakfast, Lunch and Dinner', '[{\"id\":\"blk-922f18d2-9268-4339-875d-9c5956103ece\",\"type\":\"text\",\"text\":\"Today is the highlight of your safari! After an early breakfast, head to the park headquarters for registration and a comprehensive briefing by Uganda Wildlife Authority rangers. Learn about gorilla behavior, trekking etiquette, and safety protocols before being assigned to your gorilla family and ranger guides.\\r\\n\\r\\nBegin your trek into the dense, misty forests of Bwindi in search of one of the habituated mountain gorilla families. The trek can take anywhere from 2-8 hours depending on the gorillas\' location, traversing steep terrain and thick vegetation. The moment you encounter these gentle giants in their natural habitat will be unforgettable - you\'ll have one precious hour to observe and photograph them.\\r\\n\\r\\nAfter the trek, return to your lodge for lunch and rest. In the afternoon, visit the local Batwa (Pygmy) community for an authentic cultural experience. Learn about their traditional forest lifestyle, enjoy cultural performances, and support community-based tourism initiatives.\"}]', NULL, NULL, NULL, '2026-02-01 08:16:01', '2026-02-13 06:03:50'),
(7, 4, 4, 'After breakfast, depart Bwindi and journey north to Queen Elizabeth National Park, Uganda\'s most popular savanna park and a UNESCO Biosphere Reserve. The scenic drive takes you through the dramatic landscapes of the Western Rift Valley, passing traditional villages and stunning crater lakes.\r\n\r\nArrive at Queen Elizabeth National Park in time for lunch at your safari lodge. After settling in and a brief rest, embark on your first game drive in the park\'s northern sector (Kasenyi Plains), famous for its large concentrations of Uganda kob, buffalo herds, elephants, and predators including lions and leopards.\r\n\r\nAs the sun sets over the savanna, enjoy sundowner drinks while watching the wildlife activity increase during the golden hour. Return to your lodge for dinner and overnight rest, preparing for tomorrow\'s full day of wildlife adventures.', 'Bwindi to Queen Elizabeth National Park', 'Booked hotel', NULL, 'Breakfast, Lunch and Dinner', '[{\"id\":\"blk-efb81275-65a9-4343-81ff-2ba52e7915f2\",\"type\":\"text\",\"text\":\"After breakfast, depart Bwindi and journey north to Queen Elizabeth National Park, Uganda\'s most popular savanna park and a UNESCO Biosphere Reserve. The scenic drive takes you through the dramatic landscapes of the Western Rift Valley, passing traditional villages and stunning crater lakes.\\r\\n\\r\\nArrive at Queen Elizabeth National Park in time for lunch at your safari lodge. After settling in and a brief rest, embark on your first game drive in the park\'s northern sector (Kasenyi Plains), famous for its large concentrations of Uganda kob, buffalo herds, elephants, and predators including lions and leopards.\\r\\n\\r\\nAs the sun sets over the savanna, enjoy sundowner drinks while watching the wildlife activity increase during the golden hour. Return to your lodge for dinner and overnight rest, preparing for tomorrow\'s full day of wildlife adventures.\"}]', NULL, NULL, NULL, '2026-02-01 08:16:01', '2026-02-13 06:03:50'),
(8, 4, 5, 'Start your day with an early morning game drive in the Kasenyi Plains, when wildlife is most active. Search for lions, leopards, elephants, buffalo, and various antelope species as the African sun rises over the savanna. The park is renowned for its tree-climbing lions, and you may spot them resting in fig trees.\r\n\r\nReturn to the lodge for breakfast and a midday break to escape the heat. After lunch, embark on the highlight boat safari along the famous Kazinga Channel, a natural waterway connecting Lake Edward and Lake George.\r\n\r\nThe 2-hour boat cruise offers incredible wildlife viewing opportunities - witness massive hippo pods, Nile crocodiles basking on the banks, elephants drinking at the water\'s edge, and over 600 bird species including African fish eagles, pelicans, and kingfishers. The channel has one of the highest concentrations of hippos in Africa.\r\n\r\nEvening at leisure at your lodge, enjoying the sounds of the African wilderness under starlit skies.', 'Full Day Queen Elizabeth National Park - Kazinga Channel Boat Safari', 'Booked hotel', 3, 'Breakfast, Lunch, Dinner', '[{\"id\":\"blk-9a8a0cb8-ec0c-4919-b690-2b2ab1609341\",\"type\":\"text\",\"text\":\"Start your day with an early morning game drive in the Kasenyi Plains, when wildlife is most active. Search for lions, leopards, elephants, buffalo, and various antelope species as the African sun rises over the savanna. The park is renowned for its tree-climbing lions, and you may spot them resting in fig trees.\\r\\n\\r\\nReturn to the lodge for breakfast and a midday break to escape the heat. After lunch, embark on the highlight boat safari along the famous Kazinga Channel, a natural waterway connecting Lake Edward and Lake George.\\r\\n\\r\\nThe 2-hour boat cruise offers incredible wildlife viewing opportunities - witness massive hippo pods, Nile crocodiles basking on the banks, elephants drinking at the water\'s edge, and over 600 bird species including African fish eagles, pelicans, and kingfishers. The channel has one of the highest concentrations of hippos in Africa.\\r\\n\\r\\nEvening at leisure at your lodge, enjoying the sounds of the African wilderness under starlit skies.\"},{\"id\":\"blk-97861e6a-68f2-4b39-80a8-5be85ccdbec7\",\"type\":\"image\",\"caption\":\"\",\"media_id\":9}]', NULL, NULL, NULL, '2026-02-01 08:16:01', '2026-04-03 14:08:44'),
(9, 4, 6, 'After breakfast, depart Queen Elizabeth National Park and journey east towards Lake Mburo National Park, Uganda\'s smallest savanna national park known for its rolling hills, acacia woodlands, and seasonal wetlands.\r\n\r\nEn route, stop at Igongo Cultural Centre near Mbarara for lunch and an insightful cultural experience learning about the Ankole people and their famous long-horned cattle. Explore the museum showcasing traditional Ugandan cultures and enjoy authentic local cuisine.\r\n\r\nArrive at Lake Mburo National Park in the afternoon and check into your safari lodge. Embark on an afternoon game drive through the park\'s diverse habitats, searching for zebras (the only park in Uganda with zebras), impalas, elands, buffaloes, and various bird species including the rare shoebill stork.\r\n\r\nLake Mburo is also excellent for leopard sightings, and the park\'s compact size ensures excellent wildlife viewing. End the day with sunset views over Lake Mburo, followed by dinner at your lodge.', 'Queen Elizabeth to Lake Mburo National Park - Game Drive & Cultural Visit', 'Booked hotel', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-e8995fe8-6751-40d6-83f8-da5ebe701ff7\",\"type\":\"text\",\"text\":\"After breakfast, depart Queen Elizabeth National Park and journey east towards Lake Mburo National Park, Uganda\'s smallest savanna national park known for its rolling hills, acacia woodlands, and seasonal wetlands.\\r\\n\\r\\nEn route, stop at Igongo Cultural Centre near Mbarara for lunch and an insightful cultural experience learning about the Ankole people and their famous long-horned cattle. Explore the museum showcasing traditional Ugandan cultures and enjoy authentic local cuisine.\\r\\n\\r\\nArrive at Lake Mburo National Park in the afternoon and check into your safari lodge. Embark on an afternoon game drive through the park\'s diverse habitats, searching for zebras (the only park in Uganda with zebras), impalas, elands, buffaloes, and various bird species including the rare shoebill stork.\\r\\n\\r\\nLake Mburo is also excellent for leopard sightings, and the park\'s compact size ensures excellent wildlife viewing. End the day with sunset views over Lake Mburo, followed by dinner at your lodge.\"}]', NULL, NULL, NULL, '2026-02-01 08:16:01', '2026-02-13 06:03:51'),
(10, 4, 7, 'Begin your final safari day with an optional early morning walking safari in Lake Mburo National Park - one of the few Ugandan parks where walking safaris are permitted. Accompanied by an armed ranger, explore the park on foot for a unique perspective on wildlife tracking, bird watching, and understanding the smaller details of the ecosystem often missed during game drives.\r\n\r\nAfter breakfast and checking out, enjoy a final game drive as you exit the park, capturing last-minute wildlife photography opportunities. The journey back to Entebbe takes you through Uganda\'s beautiful countryside, passing through small towns and scenic landscapes.\r\n\r\nStop for lunch en route and visit local craft markets for last-minute souvenir shopping. Arrive in Entebbe in the late afternoon with time for airport check-in procedures or optional overnight at an Entebbe hotel depending on your international flight departure time.\r\n\r\nReflect on your incredible 7-day adventure - from intimate gorilla encounters to Big Five sightings, cultural experiences, and the diverse landscapes of the \"Pearl of Africa.', 'Lake Mburo - Walking Safari & Return to Entebbe', 'Day room at airport hotel (if needed) or departure', NULL, 'Breakfast, Lunch', '[{\"id\":\"blk-5a401a7b-e65f-4fb7-bd13-36be995503e7\",\"type\":\"text\",\"text\":\"Begin your final safari day with an optional early morning walking safari in Lake Mburo National Park - one of the few Ugandan parks where walking safaris are permitted. Accompanied by an armed ranger, explore the park on foot for a unique perspective on wildlife tracking, bird watching, and understanding the smaller details of the ecosystem often missed during game drives.\\r\\n\\r\\nAfter breakfast and checking out, enjoy a final game drive as you exit the park, capturing last-minute wildlife photography opportunities. The journey back to Entebbe takes you through Uganda\'s beautiful countryside, passing through small towns and scenic landscapes.\\r\\n\\r\\nStop for lunch en route and visit local craft markets for last-minute souvenir shopping. Arrive in Entebbe in the late afternoon with time for airport check-in procedures or optional overnight at an Entebbe hotel depending on your international flight departure time.\\r\\n\\r\\nReflect on your incredible 7-day adventure - from intimate gorilla encounters to Big Five sightings, cultural experiences, and the diverse landscapes of the \\\"Pearl of Africa.\"}]', NULL, NULL, NULL, '2026-02-01 08:16:01', '2026-02-13 06:03:51'),
(18, 7, 1, 'Upon your arrival at Entebbe International Airport, you will be met by our professional safari guide, who will serve as your expert storyteller and navigator throughout your journey. A short transfer brings you to a charming lakeside midrange hotel, strategically chosen for its serene atmosphere and views of Lake Victoria. After you have refreshed from your flight, your guide will conduct a comprehensive evening briefing. This session covers the full safari route, wildlife expectations, and the vital trekking rules for primates, ensuring you are fully prepared for the adventure ahead while you enjoy a quiet dinner overlooking the water', 'Arrival & Welcome in Entebbe', '2 Friends Beach Hotel', NULL, 'Lunch (for early arrivals), Dinner', '[{\"id\":\"blk-3cea34f9-aeba-4aed-9f4d-c557f68c8073\",\"type\":\"text\",\"text\":\"On arrival at Entebbe International Airport, you are welcomed by your safari guide and transferred to a comfortable lakeside midrange hotel where you check in, refresh, and relax after your flight. In the evening, your guide briefs you about the full safari route, wildlife expectations, trekking rules, accommodation standards, and daily timing, giving you a clear mental picture of the journey ahead while you enjoy dinner and a calm overnight near Lake Victoria.\"}]', NULL, NULL, NULL, '2026-02-19 05:31:17', '2026-04-03 21:15:31'),
(19, 7, 2, 'After an early breakfast, your overland expedition begins, driving through the vibrant heart of central Uganda. This is not just a transfer; it is an immersion into local life as you pass through bustling roadside markets, lush farms, and sprawling plantations. The morning’s highlight is a visit to the Ziwa Rhino Sanctuary, the only place in Uganda where you can track wild rhinos on foot. Led by expert armed rangers, you will learn about the delicate conservation efforts required to restore these prehistoric giants to the wild. In the afternoon, you continue to Murchison Falls National Park, where the savannah begins to unfold and sightings of baboons or elegant antelope often greet you before you even reach your lodge.', 'Scenic Countryside Drive & Rhino Tracking to Murchison Falls National Park', 'Pakuba Safari Lodge', 13, 'Breakfast, Lunch, Dinner', '[{\"id\":\"blk-c427e4ac-2842-4e22-bf0f-0fcf00cd3f05\",\"type\":\"text\",\"text\":\"After breakfast you begin your overland safari journey through central Uganda\\u2019s countryside, passing villages, farms, roadside markets, and plantations, with photo stops that introduce you to local daily life. You track wild rhinos on foot with armed rangers at Ziwa Rhino Sanctuary, approaching quietly and learning how rhinos are being restored in Uganda. You then continue to Murchison Falls, arriving with views of wide savannah and the Nile corridor, often spotting baboons and antelope even before reaching your lodge.\"},{\"id\":\"blk-67e49051-6b9c-49c8-9e99-9523addeb9b5\",\"type\":\"image\",\"temp_media_id\":\"tmp-9w9ucrool\",\"caption\":\"\"}]', NULL, NULL, NULL, '2026-02-19 05:31:17', '2026-04-03 21:15:31'),
(20, 7, 3, 'After an early breakfast, witness the savannah stir to life during a sunrise game drive, a time when the air is cool and the park’s predators are at their most active. Under the guidance of your expert, you will search the open plains for lions, leopards, towering giraffes, and massive herds of buffalo. In the afternoon, the safari takes to the water with a private boat cruise toward the base of Murchison Falls. You will float past enormous pods of hippos, sunbathing Nile crocodiles, and elephants cooling off at the river’s edge. The journey concludes with a spectacular view of the Nile exploding through a narrow rock gap, sending a plume of mist and rainbows into the air', 'Sunrise Game Drive & Nile Boat Safari', 'Pakuba Safari Lodge', 13, 'Breakfast, Lunch and Dinner', '[{\"id\":\"blk-5f65879c-d2ea-43db-adde-ed7e3fc6d087\",\"type\":\"text\",\"text\":\"You head into the park at sunrise when temperatures are cool and predators are most active, searching for lions, giraffes, elephants, buffalo, and antelope across open plains while your guide explains tracks and animal behavior. In the afternoon you cruise by boat along the Nile toward the base of the falls, floating past hippo pods, giant crocodiles, elephants on the banks, and dense birdlife, finishing with dramatic views of the falls\\u2019 mist rising ahead.\"}]', NULL, NULL, NULL, '2026-02-19 05:31:18', '2026-04-03 21:15:31'),
(21, 7, 4, 'Following breakfast, you will visit the \"Top of the Falls,\" a sensory experience where you can feel the ground vibrate beneath your feet as the Nile forces itself through a narrow seven-meter gorge. From this thunderous display, the landscape shifts dramatically as you begin a scenic transfer through the Albertine Rift escarpments. You will pass through endless emerald-green tea estates and the spectacular Crater Lakes region near Fort Portal. As you arrive at your lodge near Kibale National Park, you will notice the transition to cooler highland air and the dense, ancient greenery of the rainforest', 'Top of the Falls & Transfer to Kibale National Park', 'Isunga Lodge', 15, 'Breakfast, Lunch and Dinner', '[{\"id\":\"blk-8bc4af57-ec49-456e-b83e-dcb0b96fdc17\",\"type\":\"text\",\"text\":\"You visit the top of the falls where the Nile violently forces through a narrow rock gap, creating thunder, spray, and rainbows, then begin a scenic transfer through escarpments, tea estates, and crater lake regions toward Kibale Forest, arriving in cooler highland air and lush greenery surrounding your lodge.\"},{\"id\":\"blk-0adb10bf-53dc-4a3e-911b-e5e63298db55\",\"type\":\"image\",\"temp_media_id\":\"tmp-a8exmypx5\",\"caption\":\"\"}]', NULL, NULL, NULL, '2026-02-19 05:31:18', '2026-04-03 21:15:31'),
(22, 7, 5, 'After breakfast, you will head into the tropical rainforest of Kibale with professional trackers, listening for the distinctive pant-hoots of our closest biological relatives. Once located, you will spend a regulated hour observing their fascinating social lives from feeding and grooming to their lightning-fast acrobatics in the trees. In the afternoon, the focus shifts to community conservation at the Bigodi Wetland Sanctuary. On a guided swamp walk, you will spot rare primates and birds, ending with a visit to local community groups who demonstrate traditional crafts and conservation projects', 'Chimpanzee Tracking & Wetland Community Experience', 'Isunga Lodge', NULL, 'Breakfast, Lunch, Dinner', '[{\"id\":\"blk-fb55b37a-f050-4dda-be03-518e025fbb83\",\"type\":\"text\",\"text\":\"You enter tropical forest with trackers, listening for chimp calls and movement until the troop is located, then observe their fast, social behavior  feeding, calling, climbing, and interacting at close distance. Later you explore Bigodi Wetland on a guided walk, spotting monkeys and birds while meeting local community groups who demonstrate crafts and conservation projects\"}]', NULL, NULL, NULL, '2026-02-19 05:31:18', '2026-04-03 21:17:40'),
(23, 7, 6, 'After breakfast, the drive today takes you through the dramatic \"Explosion Craters,\" a landscape of ancient volcanic basins and panoramic viewpoints. As you descend toward the floor of the Rift Valley, you will enter Queen Elizabeth National Park, a biosphere of incredible diversity. Keep your binoculars ready; the transition from forest to savannah often brings immediate sightings of elephants, buffalo, or waterbuck along the very roads leading to your midrange lodge.', 'Crater Lakes Region to Queen Elizabeth National Park', 'Elephant Hab Lodge,', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-163ab7dc-7af6-42ab-b70c-bb94b55cdb86\",\"type\":\"text\",\"text\":\"You drive through volcanic crater landscapes dotted with small lakes and panoramic viewpoints, stopping for photos and short walks, before entering Queen Elizabeth National Park where open savannah begins and wildlife sightings often start immediately along the road to your lodge.\"}]', NULL, NULL, NULL, '2026-02-19 05:31:18', '2026-04-03 21:15:31'),
(24, 7, 7, 'After an early breakfast, start your day with an intensive morning game drive across predator-rich plains, searching for lions and large herbivore herds. Your guide will decode animal tracks and behaviors, offering a masterclass in African ecology. The afternoon provides arguably the most relaxed yet productive wildlife viewing of the trip: a boat safari on the Kazinga Channel. Here, the wildlife comes to you. You will cruise within meters of hippos, while elephants and buffalo gather at the shoreline to drink, and an incredible array of water birds fills the sky and banks', 'savannah Game Drive & Kazinga Channel Boat Safari', 'Elephant Hab Lodge,', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-9458bace-dba1-4286-8ede-2314fdcef77c\",\"type\":\"text\",\"text\":\"You explore predator-rich plains in the morning, searching for lions and large herbivore herds, then take an afternoon boat safari on the Kazinga Channel where hippos crowd the water, elephants drink at the shoreline, buffalo gather in large numbers, and water birds are abundant \\u2014 one of the closest-range wildlife viewing experiences of the trip.\"},{\"id\":\"blk-94ab54b2-e9fc-4ca8-8c7b-925928350a75\",\"type\":\"image\",\"temp_media_id\":\"tmp-3dbumgspr\",\"caption\":\"\"}]', NULL, NULL, NULL, '2026-02-19 05:31:18', '2026-04-03 21:15:31'),
(25, 7, 8, 'Have breakfast, you embark on the journey toward the southern sector of the park through Ishasha, a region famous for its tree-climbing lions. You will search the expansive limbs of ancient fig trees for these majestic cats, a rare behavior found in only a few places on the continent. Leaving the savannah behind, you begin the climb into the rising highlands. The air grows crisp and the hills become steeper and more terraced as you approach the misty borders of Bwindi Impenetrable National Park, the ancient home of the mountain gorillas', 'ishasha Tree-Climbing Lions & Transfer to Bwindi Impenetrable National Park', 'Bakiga Lodge', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-b06feef8-09ee-43d2-8967-bdaa1bd43564\",\"type\":\"text\",\"text\":\"Driving through the Ishasha sector, you search fig trees for the famous tree-climbing lions  a rare behavior  then continue into rising highlands and misty forest landscapes as you approach Bwindi, the home of mountain gorillas.\\n\\nPossible Lodges: Ichu\"},{\"id\":\"blk-0aeaa0c8-a6c9-475a-b265-3c4f068f1d81\",\"type\":\"image\",\"temp_media_id\":\"tmp-vetd7ocyk\",\"caption\":\"\"}]', NULL, NULL, NULL, '2026-02-19 05:31:18', '2026-04-03 21:15:31'),
(26, 7, 9, 'After a hearty breakfast, you will enter the dense, prehistoric rainforest with expert rangers in search of a mountain gorilla family. The trek can be physically demanding, through thick vegetation and across steep ridges, but all effort vanishes the moment you find them. You will spend one quiet, profound hour just meters away from the family, watching the Silverback protect his troop while mothers nurture their young and juveniles play. Most travelers describe this emotional and powerful encounter as life-changing', 'Gorilla Trekking Experience', 'Bakiga Lodge', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-95186194-878f-4c30-9504-4af7d537d0e7\",\"type\":\"text\",\"text\":\"You trek through dense rainforest with rangers, sometimes for several hours, following fresh signs until you encounter a gorilla family, where you spend one regulated hour observing their social life \\u2014 silverbacks guarding, juveniles playing, mothers nurturing \\u2014 an emotional and powerful wildlife encounter that most travelers describe as life-changing.\"},{\"id\":\"blk-3523c420-9c36-418c-8f59-2054bafee097\",\"type\":\"image\",\"temp_media_id\":\"tmp-5k8kz373b\",\"caption\":\"\"}]', NULL, NULL, NULL, '2026-02-19 05:31:18', '2026-04-03 21:15:31'),
(27, 7, 10, 'After breakfast, we have intentionally designed this day for recovery and deeper connection. You may choose to spend a slow morning at the lodge, soaking in the views of the forest canopy. Later, participate in a guided village walk, where you can visit local craft groups or join a cultural performance. These interactions provide vital context, showing how the local communities live alongside the gorilla habitat and the importance of conservation to their daily lives', 'Forest Edge Relaxation & Community Visit around Bwindi', 'Bakiga Lodge', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-b0d6d1a8-1337-4780-8842-c750960d9bbc\",\"type\":\"text\",\"text\":\"After the physical trek, this day is intentionally lighter, allowing you to rest at the lodge, enjoy forest views, take a guided village walk, visit local craft groups, or join a cultural performance giving context to the communities living alongside gorilla habitat.\"}]', NULL, NULL, NULL, '2026-02-19 05:31:18', '2026-04-03 21:15:31'),
(28, 7, 11, 'After breakfast, a scenic drive takes you to Lake Bunyonyi, a highland lake surrounded by 29 islands and steep terraced hills. This is your time to unwind. You can explore the lake by traditional dugout canoe, take photographs of the mist-covered hills, or simply enjoy a book on the lakeside. For those seeking more activity, the lake is bilharzia-free and safe for swimming.', 'Transfer to Lake Bunyonyi', 'Lake Bunyonyi Eco Resort', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-d6ba21f7-3bf0-450a-ae56-16d34824f990\",\"type\":\"text\",\"text\":\"You drive to Lake Bunyonyi, a scenic highland lake surrounded by terraced hills and dotted with islands, where you unwind with canoe rides, lakeside relaxation, photography, and optional swimming in bilharzia-free waters.\"},{\"id\":\"blk-9b72c96e-d474-46f8-8044-5a9d24c66cbf\",\"type\":\"image\",\"temp_media_id\":\"tmp-i7ugy0da4\",\"caption\":\"\"}]', NULL, NULL, NULL, '2026-02-19 05:31:18', '2026-04-03 21:15:31'),
(29, 7, 12, 'After breakfast, the safari continues to Lake Mburo National Park, a unique ecosystem characterized by acacia woodlands and shimmering lakes. This park is the best place in Uganda to see zebras, impalas, and the massive Eland antelope. You will arrive in time for an evening game drive as the sun begins to set, casting a golden glow over the savannah and providing excellent lighting for photography as the wildlife becomes active', 'Transfer to Lake Mburo National Park & Evening Game Drive', 'Mburo Safari Lodge', NULL, '', '[{\"id\":\"blk-7c1456a4-9859-4a11-99c4-2cfd94d43953\",\"type\":\"text\",\"text\":\"You travel to Lake Mburo National Park, known for zebras, elands, giraffes, and impalas, arriving for an evening game drive in golden light with close sightings and beautiful acacia woodland scenery.\"},{\"id\":\"blk-c22dcc36-0073-406b-9744-ee808483de85\",\"type\":\"image\",\"temp_media_id\":\"tmp-duflmi3ff\",\"caption\":\"\"}]', NULL, NULL, NULL, '2026-02-19 05:31:18', '2026-04-03 21:15:31'),
(30, 7, 13, 'After breakfast, experience the African bush on its own terms with a morning walking safari. Accompanied by an armed ranger, you will leave the vehicle behind to learn the subtle language of the wild identifying tracks, plants, and animal behavior at ground level. In the afternoon, a final relaxed boat ride on Lake Mburo offers a peaceful conclusion to your wildlife viewing, with opportunities to see hippos, crocodiles, and water birds from the waterline.', 'Walking Safari & Boat Ride on Lake Mburo', 'Mburo Safari Lodge', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-56ab16f6-c829-4d0f-a36f-95b5f55523f9\",\"type\":\"text\",\"text\":\"You explore the park on foot with a ranger, learning tracks, plants, and animal behavior at ground level a very different perspective from vehicle safaris then enjoy a relaxed boat ride on Lake Mburo to see hippos, crocodiles, and water birds from the waterline.\"}]', NULL, NULL, NULL, '2026-02-19 05:31:18', '2026-04-03 21:15:31'),
(31, 7, 14, 'You drive back toward Entebbe with a stop at the Equator line for photos and demonstrations, enjoy lunch en route, and continue to the airport or hotel dropAfter breakfast, your final day includes a scenic drive back toward the capital, with a significant stop at the Equator line. Here, you can participate in water demonstrations that illustrate the hemispheres, take iconic photos, and enjoy lunch en route. Finally, your guide will transfer you to Entebbe International Airport or your hotel, concluding a comprehensive and deeply rewarding 14-day odyssey through the Pearl of Africaoff, closing a complete, well-paced midrange Uganda safari.', 'Equator Stop & Return to Entebbe', '', NULL, 'breakfast, lunch', '[{\"id\":\"blk-40ee5495-e955-4781-9212-474acee600ec\",\"type\":\"text\",\"text\":\"You drive back toward Entebbe with a stop at the Equator line for photos and demonstrations, enjoy lunch en route, and continue to the airport or hotel drop-off, closing a complete, well-paced midrange Uganda safari.\"}]', NULL, NULL, NULL, '2026-02-19 05:31:18', '2026-04-03 21:15:31'),
(32, 8, 1, 'After landing at Entebbe, you’ll be met by our team and whisked away to your guesthouse. Once you’ve checked in and freshened up, you can spend the afternoon strolling through the botanical gardens or simply relaxing with a cold drink as you adjust to the tropical rhythm. Dinner is served at the lodge, offering your first taste of local flavors.', 'Arrival & The Warm Welcome', '', NULL, 'Lunch (for early arrivals), Dinner', '[{\"id\":\"blk-a08f27f3-3545-47ed-a503-4c69ad4582fd\",\"type\":\"text\",\"text\":\"After landing at Entebbe, you\\u2019ll be met by our team and whisked away to your guesthouse. Once you\\u2019ve checked in and freshened up, you can spend the afternoon strolling through the botanical gardens or simply relaxing with a cold drink as you adjust to the tropical rhythm. Dinner is served at the lodge, offering your first taste of local flavors.\"}]', NULL, NULL, NULL, '2026-03-28 20:38:41', '2026-03-28 20:38:41'),
(33, 8, 2, 'Fuel up with an early breakfast before we hit the road heading north. By midday, you’ll reach Ziwa Rhino Sanctuary; after a quick safety briefing, you’ll head out on foot with a ranger to track the Southern White Rhinos. Following this exhilarating encounter, you\'ll settle into your nearby lodge for a quiet evening surrounded by the sounds of the savanna.', 'Transfer to Ziwa Sanctuary for Rhinos', '', NULL, 'Breakfast, Lunch, Dinner', '[{\"id\":\"blk-a316e939-9546-4550-b359-55d06d990b7c\",\"type\":\"text\",\"text\":\"Fuel up with an early breakfast before we hit the road heading north. By midday, you\\u2019ll reach Ziwa Rhino Sanctuary; after a quick safety briefing, you\\u2019ll head out on foot with a ranger to track the Southern White Rhinos. Following this exhilarating encounter, you\'ll settle into your nearby lodge for a quiet evening surrounded by the sounds of the savanna.\"},{\"id\":\"blk-c417c3a0-a57b-4160-8f03-28e03470eeab\",\"type\":\"image\",\"caption\":\"\",\"media_id\":13}]', NULL, NULL, NULL, '2026-03-28 20:38:41', '2026-04-01 16:31:11'),
(34, 8, 3, 'After a hearty breakfast, we continue our journey into Murchison Falls National Park. We’ll drive straight to the \"Top of the Falls,\" where you’ll hop out to experience the ground shaking beneath you as the Nile squeezes through a tiny gorge. After taking in the views and snapping photos, you’ll check into your  accommodation just in time for a sunset dinner and overnight stay.', 'Murchison Falls National Park', '', NULL, 'Breakfast, Lunch and Dinner', '[{\"id\":\"blk-ddc618e8-3044-4169-a862-4d9032cbc686\",\"type\":\"text\",\"text\":\"After a hearty breakfast, we continue our journey into Murchison Falls National Park. We\\u2019ll drive straight to the \\\"Top of the Falls,\\\" where you\\u2019ll hop out to experience the ground shaking beneath you as the Nile squeezes through a tiny gorge. After taking in the views and snapping photos, you\\u2019ll check into your  accommodation just in time for a sunset dinner and overnight stay.\"},{\"id\":\"blk-569e384c-3518-4191-86fd-3493ce72df8b\",\"type\":\"image\",\"caption\":\"\",\"media_id\":14}]', NULL, NULL, NULL, '2026-03-28 20:38:41', '2026-04-01 16:31:11'),
(35, 8, 4, 'Grab a quick coffee and head out for a sunrise game drive while the predators are still active. You’ll spend the morning spotting giraffes and lions before returning to the lodge for a midday brunch and a rest. In the afternoon, you’ll board a boat for a three-hour safari up the Nile to the base of the falls, watching hippos and crocodiles along the banks before heading back for a relaxing evening', 'Sunrise game drive & boat cruise', '', NULL, 'Breakfast, Lunch and Dinner', '[{\"id\":\"blk-28e63bba-255e-4c12-8446-fcfdb89c36fb\",\"type\":\"text\",\"text\":\"Grab a quick coffee and head out for a sunrise game drive while the predators are still active. You\\u2019ll spend the morning spotting giraffes and lions before returning to the lodge for a midday brunch and a rest. In the afternoon, you\\u2019ll board a boat for a three-hour safari up the Nile to the base of the falls, watching hippos and crocodiles along the banks before heading back for a relaxing evening\"},{\"id\":\"blk-1569ecdd-23f5-4c2d-9912-7eb2f6c54c72\",\"type\":\"image\",\"temp_media_id\":\"tmp-zqblsb1or\",\"caption\":\"\"},{\"id\":\"blk-2de8830d-2ac3-4429-951c-f365ed022cf0\",\"type\":\"image\",\"caption\":\"\",\"media_id\":15}]', NULL, NULL, NULL, '2026-03-28 20:38:41', '2026-04-01 16:31:11'),
(36, 8, 5, 'Enjoy breakfast overlooking the river before we begin a scenic full-day transit. You’ll wind through the Albertine Rift Valley and the lush green tea plantations of Fort Portal, stopping for a local lunch along the way. By late afternoon, you’ll pull into the Kibale Forest region, where the air is cool and the sounds of primates fill the canopy.', 'Through the Tea Estates to the Kibale  Forest  National park', '', NULL, 'Breakfast, Lunch, Dinner', '[{\"id\":\"blk-eb9e6688-841c-4901-a6e3-548a486c1208\",\"type\":\"text\",\"text\":\"Enjoy breakfast overlooking the river before we begin a scenic full-day transit. You\\u2019ll wind through the Albertine Rift Valley and the lush green tea plantations of Fort Portal, stopping for a local lunch along the way. By late afternoon, you\\u2019ll pull into the Kibale Forest region, where the air is cool and the sounds of primates fill the canopy.\"}]', NULL, NULL, NULL, '2026-03-28 20:38:41', '2026-03-28 20:38:41'),
(37, 8, 6, 'After an early breakfast, you’ll head to the forest headquarters for your Chimpanzee tracking adventure. You’ll spend the morning deep in the jungle observing our closest relatives; then, after a forest lunch, you’ll head to the Bigodi Wetland. Here, you’ll take a guided community walk to spot rare birds and monkeys, ending the day with a traditional dinner back at your forest camp.', 'Chimps and Community Walks', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-7a410cb7-0dcb-4ba1-a10f-fbc60d4638fd\",\"type\":\"text\",\"text\":\"After an early breakfast, you\\u2019ll head to the forest headquarters for your Chimpanzee tracking adventure. You\\u2019ll spend the morning deep in the jungle observing our closest relatives; then, after a forest lunch, you\\u2019ll head to the Bigodi Wetland. Here, you\\u2019ll take a guided community walk to spot rare birds and monkeys, ending the day with a traditional dinner back at your forest camp.\"},{\"id\":\"blk-9df17d47-6429-4517-ae37-b5eea4d179e4\",\"type\":\"image\",\"temp_media_id\":\"tmp-bq7iwotpp\",\"caption\":\"\"},{\"id\":\"blk-11ea7628-f03e-48bd-ac28-1719a11eb9dc\",\"type\":\"image\",\"caption\":\"\",\"media_id\":16}]', NULL, NULL, NULL, '2026-03-28 20:38:41', '2026-03-28 20:38:41'),
(38, 8, 7, 'Enjoy a relaxed breakfast before we explore the stunning \"Top of the World\" crater lakes. After taking in the panoramic views, we’ll descend into Queen Elizabeth National Park. As you enter the park, you’ll transition straight into an evening game drive, spotting elephants and buffaloes as they move toward water holes, followed by a cozy night at your safari cottage', 'Craters and then transfer to  Queen Elizabeth National Park', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-f127eaf0-b396-47bc-b3ba-3a1d443f4fa1\",\"type\":\"text\",\"text\":\"Enjoy a relaxed breakfast before we explore the stunning \\\"Top of the World\\\" crater lakes. After taking in the panoramic views, we\\u2019ll descend into Queen Elizabeth National Park. As you enter the park, you\\u2019ll transition straight into an evening game drive, spotting elephants and buffaloes as they move toward water holes, followed by a cozy night at your safari cottage\"},{\"id\":\"blk-3de81772-c396-4417-acd4-4fe0c6419fa9\",\"type\":\"image\",\"temp_media_id\":\"tmp-1ixm39pg1\",\"caption\":\"\"},{\"id\":\"blk-f6600102-b836-4775-a1ff-8adec6ada67e\",\"type\":\"image\",\"caption\":\"\",\"media_id\":17}]', NULL, NULL, NULL, '2026-03-28 20:38:41', '2026-03-28 20:38:41'),
(39, 8, 8, 'Coffee is served at dawn before you head into the Kasenyi plains to catch lions and leopards on the move. You’ll return to the lodge for lunch and a siesta during the heat of the day. In the afternoon, you’ll head to the water for a boat cruise along the Kazinga Channel prepare for incredible close-ups of hippos and elephants before returning for dinner under the stars.', 'Predators & The Kazinga Channel', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-352c6b15-2988-4a9c-bee6-92880af6ced5\",\"type\":\"text\",\"text\":\"Coffee is served at dawn before you head into the Kasenyi plains to catch lions and leopards on the move. You\\u2019ll return to the lodge for lunch and a siesta during the heat of the day. In the afternoon, you\\u2019ll head to the water for a boat cruise along the Kazinga Channel prepare for incredible close-ups of hippos and elephants before returning for dinner under the stars.\"},{\"id\":\"blk-37a017df-f9e3-4cc1-82fa-32bbcc42a4a8\",\"type\":\"image\",\"temp_media_id\":\"tmp-x3vybhstw\",\"caption\":\"\"},{\"id\":\"blk-45dedc66-4f78-47de-aeef-ae5a98ec5035\",\"type\":\"image\",\"temp_media_id\":\"tmp-x63yethqi\",\"caption\":\"\"},{\"id\":\"blk-3e69f5f7-0ee4-442f-83e7-c8f50aa15086\",\"type\":\"image\",\"caption\":\"\",\"media_id\":18}]', NULL, NULL, NULL, '2026-03-28 20:38:41', '2026-03-28 20:38:41'),
(40, 8, 9, 'After breakfast, we pack up and head to the remote Ishasha sector. You’ll spend the day traversing the plains with your eyes glued to the giant fig trees, searching for the famous lions that lounge in the branches. After a picnic lunch in the wild, you’ll check into your safari camp for a more secluded, \"off-the-grid\" evening experience.', 'Seeking the Tree-Climbing Lions', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-3e088ba8-310b-43e7-a785-eae4c6f1cd66\",\"type\":\"text\",\"text\":\"After breakfast, we pack up and head to the remote Ishasha sector. You\\u2019ll spend the day traversing the plains with your eyes glued to the giant fig trees, searching for the famous lions that lounge in the branches. After a picnic lunch in the wild, you\\u2019ll check into your safari camp for a more secluded, \\\"off-the-grid\\\" evening experience.\"},{\"id\":\"blk-eaff1f90-e7d0-4482-9395-72154cf1aa8f\",\"type\":\"image\",\"temp_media_id\":\"tmp-j8ou2xya8\",\"caption\":\"\"},{\"id\":\"blk-c4e5b53c-49b4-48bd-8b50-af3c82384ed9\",\"type\":\"image\",\"temp_media_id\":\"tmp-vfd29vkub\",\"caption\":\"\"},{\"id\":\"blk-b2364b6b-3430-4929-b3f5-601913644771\",\"type\":\"image\",\"caption\":\"\",\"media_id\":19}]', NULL, NULL, NULL, '2026-03-28 20:38:41', '2026-03-28 20:38:41'),
(41, 8, 10, 'Enjoy a final Ishasha breakfast before we drive toward Lake Mburo National Park. You’ll pass through the rolling hills of Ankole, stopping to admire the iconic long-horned cattle. Upon arrival, you’ll head out for a late afternoon game drive to see the zebras and impalas that make this park unique, ending the day at a lodge with views over the acacia valleys.', 'Transfer To lake Mburo, the Land of Zebras', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-afcdef33-6840-4d9f-8f27-dc77a0e6fea0\",\"type\":\"text\",\"text\":\"Enjoy a final Ishasha breakfast before we drive toward Lake Mburo National Park. You\\u2019ll pass through the rolling hills of Ankole, stopping to admire the iconic long-horned cattle. Upon arrival, you\\u2019ll head out for a late afternoon game drive to see the zebras and impalas that make this park unique, ending the day at a lodge with views over the acacia valleys.\"},{\"id\":\"blk-cc45b3cf-0997-47f9-90ae-bcef61601222\",\"type\":\"image\",\"temp_media_id\":\"tmp-v5u1c3e08\",\"caption\":\"\"},{\"id\":\"blk-9caaddf0-aa30-4165-8c84-fdbc6df608d0\",\"type\":\"image\",\"temp_media_id\":\"tmp-7za5ikv6j\",\"caption\":\"\"}]', NULL, NULL, NULL, '2026-03-28 20:38:41', '2026-03-28 20:38:41'),
(42, 8, 11, 'Skip the vehicle this morning; after breakfast, you’ll join an armed ranger for a guided walking safari. You’ll experience the thrill of being on the same level as the wildlife, walking among giraffes and zebras. In the afternoon, you’ll enjoy a final tranquil boat ride on Lake Mburo to spot the elusive African Finfoot, followed by a farewell dinner at the lodge.', 'The Wild on Foot', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-51d64fee-f2c0-466a-9a33-8135bc73aac1\",\"type\":\"text\",\"text\":\"Skip the vehicle this morning; after breakfast, you\\u2019ll join an armed ranger for a guided walking safari. You\\u2019ll experience the thrill of being on the same level as the wildlife, walking among giraffes and zebras. In the afternoon, you\\u2019ll enjoy a final tranquil boat ride on Lake Mburo to spot the elusive African Finfoot, followed by a farewell dinner at the lodge.\"},{\"id\":\"blk-8871bbb5-2e0b-4c77-9c6a-2614bf785956\",\"type\":\"image\",\"temp_media_id\":\"tmp-sb6ovps6f\",\"caption\":\"\"},{\"id\":\"blk-f003ae4d-99fe-4783-877b-632df51a7ac7\",\"type\":\"image\",\"caption\":\"\",\"media_id\":20}]', NULL, NULL, NULL, '2026-03-28 20:38:41', '2026-03-28 20:38:41'),
(43, 8, 12, 'After one last breakfast in the bush, we begin our return journey toward the capital. We’ll stop at the Equator crossing for the famous water experiment and some souvenir shopping at the local markets. After a final group lunch, we’ll transfer you to Entebbe Airport for your evening flight, leaving you with a lifetime of Ugandan memories.', 'The Equator & The Journey Home', '', NULL, 'breakfast, lunch', '[{\"id\":\"blk-1dcfc356-e37c-4fff-a4fb-5b6caf8158af\",\"type\":\"text\",\"text\":\"After one last breakfast in the bush, we begin our return journey toward the capital. We\\u2019ll stop at the Equator crossing for the famous water experiment and some souvenir shopping at the local markets. After a final group lunch, we\\u2019ll transfer you to Entebbe Airport for your evening flight, leaving you with a lifetime of Ugandan memories.\"}]', NULL, NULL, NULL, '2026-03-28 20:38:41', '2026-03-28 20:38:41'),
(44, 9, 1, 'Upon arrival at Entebbe International Airport, your personal guide will welcome you and transfer you to a boutique mid-range hotel overlooking Lake Victoria. After checking in, the afternoon is yours to stroll through the Entebbe Botanical Gardens or enjoy a sunset drink on the pier. Dinner is served at the hotel, allowing you to settle into the Ugandan rhythm', 'Arrival & Lakeside Calm', '', NULL, 'Lunch (for early arrivals), Dinner', '[{\"id\":\"blk-f168269d-703a-4a3e-b759-e68d52fd7d91\",\"type\":\"text\",\"text\":\"Upon arrival at Entebbe International Airport, your personal guide will welcome you and transfer you to a boutique mid-range hotel overlooking Lake Victoria. After checking in, the afternoon is yours to stroll through the Entebbe Botanical Gardens or enjoy a sunset drink on the pier. Dinner is served at the hotel, allowing you to settle into the Ugandan rhythm\"}]', NULL, NULL, NULL, '2026-03-28 21:24:48', '2026-03-28 21:24:48'),
(45, 9, 2, 'After a relaxed breakfast, we begin our journey north through the green landscapes of central Uganda. By midday, you’ll reach Ziwa Rhino Sanctuary for an exhilarating trek on foot to see the endangered Southern White Rhinos. Following the trek, you will check into a beautiful lodge within the sanctuary where you can enjoy a sundowner on your private veranda as the savanna cools down.', 'Rhino tracking ziwa Sanctuary', '', NULL, 'Breakfast, Lunch, Dinner', '[{\"id\":\"blk-dd799e7d-1fdc-4b40-a04a-f8129b718aa2\",\"type\":\"text\",\"text\":\"After a relaxed breakfast, we begin our journey north through the green landscapes of central Uganda. By midday, you\\u2019ll reach Ziwa Rhino Sanctuary for an exhilarating trek on foot to see the endangered Southern White Rhinos. Following the trek, you will check into a beautiful lodge within the sanctuary where you can enjoy a sundowner on your private veranda as the savanna cools down.\"}]', NULL, NULL, NULL, '2026-03-28 21:24:48', '2026-03-28 21:24:48'),
(46, 9, 3, 'Fuel up with a hearty breakfast before we enter Murchison Falls National Park. We head straight to the \"Top of the Falls\" to feel the spray and hear the thunderous roar as the Nile River forces itself through a narrow gorge. You’ll then cross the river to your mid-range safari lodge, featuring elevated views of the Albert Nile and frequent visits from resident hippos.', 'The Mighty Nile & Murchison Falls', '', NULL, 'Breakfast, Lunch and Dinner', '[{\"id\":\"blk-f088916f-14dc-4cd0-abde-dd45c0c0cec7\",\"type\":\"text\",\"text\":\"Fuel up with a hearty breakfast before we enter Murchison Falls National Park. We head straight to the \\\"Top of the Falls\\\" to feel the spray and hear the thunderous roar as the Nile River forces itself through a narrow gorge. You\\u2019ll then cross the river to your mid-range safari lodge, featuring elevated views of the Albert Nile and frequent visits from resident hippos.\"}]', NULL, NULL, NULL, '2026-03-28 21:24:48', '2026-03-28 21:24:48');
INSERT INTO `tour_itinerary` (`id`, `tour_id`, `day_number`, `activity`, `day_title`, `accommodation`, `accommodation_id`, `meals`, `content_blocks`, `cover_media_id`, `cover_caption`, `updated_by`, `created_at`, `updated_at`) VALUES
(47, 9, 4, 'Sip on locally grown coffee before heading out for a sunrise game drive to spot lions, leopards, and the rare Rothschild giraffes. After a midday break by the lodge pool, you’ll board a boat cruise upstream. You’ll drift past massive crocodiles and pods of hippos to the base of the falls, ending the day with a delicious three-course dinner back at the lodge.', 'Sunrise Savanna & Nile Launch Cruise', '', NULL, 'Breakfast, Lunch and Dinner', '[{\"id\":\"blk-4cc2837c-f97c-448b-a912-d0641e87e492\",\"type\":\"text\",\"text\":\"Sip on locally grown coffee before heading out for a sunrise game drive to spot lions, leopards, and the rare Rothschild giraffes. After a midday break by the lodge pool, you\\u2019ll board a boat cruise upstream. You\\u2019ll drift past massive crocodiles and pods of hippos to the base of the falls, ending the day with a delicious three-course dinner back at the lodge.\"}]', NULL, NULL, NULL, '2026-03-28 21:24:48', '2026-03-28 21:24:48'),
(48, 9, 5, 'After breakfast, we begin a scenic transit toward the primate capital, Kibale. This drive offers panoramic views of the Albertine Rift Valley and the shimmering waters of Lake Albert. You’ll wind through the vibrant green tea estates of Fort Portal before arriving at a high-quality forest lodge nestled right on the edge of the primate-filled canopy.', 'Transfer to Kibale Forest National Park', '', NULL, 'Breakfast, Lunch, Dinner', '[{\"id\":\"blk-4d091ac8-bb97-4943-a102-434b5e474d96\",\"type\":\"text\",\"text\":\"After breakfast, we begin a scenic transit toward the primate capital, Kibale. This drive offers panoramic views of the Albertine Rift Valley and the shimmering waters of Lake Albert. You\\u2019ll wind through the vibrant green tea estates of Fort Portal before arriving at a high-quality forest lodge nestled right on the edge of the primate-filled canopy.\"}]', NULL, NULL, NULL, '2026-03-28 21:24:48', '2026-03-28 21:24:48'),
(49, 9, 6, 'The morning begins with the adrenaline of Chimpanzee tracking; you’ll spend an hour observing our closest relatives in their natural rainforest home. After a forest-to-table lunch, you’ll join a guided walk through the Bigodi Wetland Sanctuary to spot the Great Blue Turaco. The evening is spent relaxing by the lodge’s fireplace, sharing stories of the day’s sightings', 'Chimpanzee Tracking & Bigodi Wetland Walk', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-c4859ffa-fbfd-4637-9bcb-7325a0a350d4\",\"type\":\"text\",\"text\":\"The morning begins with the adrenaline of Chimpanzee tracking; you\\u2019ll spend an hour observing our closest relatives in their natural rainforest home. After a forest-to-table lunch, you\\u2019ll join a guided walk through the Bigodi Wetland Sanctuary to spot the Great Blue Turaco. The evening is spent relaxing by the lodge\\u2019s fireplace, sharing stories of the day\\u2019s sightings\"}]', NULL, NULL, NULL, '2026-03-28 21:24:48', '2026-03-28 21:24:48'),
(50, 9, 7, 'Enjoy a leisurely breakfast before we explore the stunning Ndali-Kasenda crater lakes ancient volcanic calderas with 360-degree views. We then descend into Queen Elizabeth National Park for an evening game drive. Your mid-range lodge for the next two nights sits on a ridge, offering a stunning vista of the savanna and the Kazinga Channel.', 'Crater Lakes & Queen Elizabeth NP', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-30fce6e9-110a-4fab-ad91-d32f112e5b06\",\"type\":\"text\",\"text\":\"Enjoy a leisurely breakfast before we explore the stunning Ndali-Kasenda crater lakes ancient volcanic calderas with 360-degree views. We then descend into Queen Elizabeth National Park for an evening game drive. Your mid-range lodge for the next two nights sits on a ridge, offering a stunning vista of the savanna and the Kazinga Channel.\"}]', NULL, NULL, NULL, '2026-03-28 21:24:48', '2026-03-28 21:24:48'),
(51, 9, 8, 'An early breakfast is followed by a search for lions and hyenas across the open plains. After returning for lunch and a siesta, you’ll embark on a boat cruise along the Kazinga Channel. This is a photographer’s dream, with elephants and buffaloes lining the banks just meters away. Dinner is served under the stars at your ridge-top retreat.', 'Savanna Predators & The Kazinga Channel', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-d4ccdb40-c56e-47ad-aeef-2b2e607fb2c2\",\"type\":\"text\",\"text\":\"An early breakfast is followed by a search for lions and hyenas across the open plains. After returning for lunch and a siesta, you\\u2019ll embark on a boat cruise along the Kazinga Channel. This is a photographer\\u2019s dream, with elephants and buffaloes lining the banks just meters away. Dinner is served under the stars at your ridge-top retreat.\"}]', NULL, NULL, NULL, '2026-03-28 21:24:48', '2026-03-28 21:24:48'),
(52, 9, 9, 'After breakfast, we pack up and head to the remote southern sector of the park. You’ll spend the afternoon scanning the massive fig trees for the famous tree-climbing lions of Ishasha. You’ll check into a mid-range tented camp situated along the Ntungwe River, where you can watch elephants crossing the water right from your room’s deck.', 'The Tree-Climbing Lions of Ishasha', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-98491af5-3900-419b-ba75-6171a01a5ad6\",\"type\":\"text\",\"text\":\"After breakfast, we pack up and head to the remote southern sector of the park. You\\u2019ll spend the afternoon scanning the massive fig trees for the famous tree-climbing lions of Ishasha. You\\u2019ll check into a mid-range tented camp situated along the Ntungwe River, where you can watch elephants crossing the water right from your room\\u2019s deck.\"}]', NULL, NULL, NULL, '2026-03-28 21:24:48', '2026-03-28 21:24:48'),
(53, 9, 10, 'Enjoy a final morning drive in Ishasha before we ascend into the Kigezi Highlands. The air turns crisp as we reach the ancient Bwindi Impenetrable Forest. Your lodge tonight is a beautiful mid-range property overlooking the forest canopy, providing the perfect atmosphere for the big day ahead.', 'Game drive and Transfer to Bwindi Impenertable National Park', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-7e51de9d-e55d-4e9e-9c82-94be7a345717\",\"type\":\"text\",\"text\":\"Enjoy a final morning drive in Ishasha before we ascend into the Kigezi Highlands. The air turns crisp as we reach the ancient Bwindi Impenetrable Forest. Your lodge tonight is a beautiful mid-range property overlooking the forest canopy, providing the perfect atmosphere for the big day ahead.\"}]', NULL, NULL, NULL, '2026-03-28 21:24:48', '2026-03-28 21:24:48'),
(54, 9, 11, 'This is the highlight of your journey. After an early breakfast and a briefing, you’ll head into the thick rainforest with expert trackers to find a family of Mountain Gorillas. Sitting just meters away from these gentle giants for one hour is a life-changing experience. After the trek, you’ll return to the lodge for a well-deserved \"gorilla-strength\" meal.', 'The Ultimate Encounter: Gorilla Trekking', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-592e24e5-6572-4b98-ad83-42bc95d2e67b\",\"type\":\"text\",\"text\":\"This is the highlight of your journey. After an early breakfast and a briefing, you\\u2019ll head into the thick rainforest with expert trackers to find a family of Mountain Gorillas. Sitting just meters away from these gentle giants for one hour is a life-changing experience. After the trek, you\\u2019ll return to the lodge for a well-deserved \\\"gorilla-strength\\\" meal.\"}]', NULL, NULL, NULL, '2026-03-28 21:24:48', '2026-03-28 21:24:48'),
(55, 9, 12, 'After a slow breakfast, we leave the forest behind and drive to Lake Bunyonyi, the deepest and arguably most beautiful lake in Uganda. You’ll check into a mid-range resort perched on a quiet hillside. The afternoon is yours to relax, enjoy the lake views, or take a refreshing swim in the bilharzia-free waters.', 'To the Shores of Lake Bunyonyi', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-af0ba3b3-b6b2-4743-b213-6f060b2fc4ba\",\"type\":\"text\",\"text\":\"After a slow breakfast, we leave the forest behind and drive to Lake Bunyonyi, the deepest and arguably most beautiful lake in Uganda. You\\u2019ll check into a mid-range resort perched on a quiet hillside. The afternoon is yours to relax, enjoy the lake views, or take a refreshing swim in the bilharzia-free waters.\"}]', NULL, NULL, NULL, '2026-03-28 21:24:48', '2026-03-28 21:24:48'),
(56, 9, 13, 'Spend your morning and early afternoon entirely at leisure take a traditional dugout canoe to explore the lake’s 29 islands or visit a local community. Following a late afternoon tea, we will begin the drive toward Lake Mburo National Park. Arriving in the evening, you\'ll check into your lodge for dinner, ready to wake up already inside the park the next morning.', 'Island Exploration & Evening Transit to Mburo', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-81ac5c5a-fcd1-46de-89ab-b3d664076fbf\",\"type\":\"text\",\"text\":\"Spend your morning and early afternoon entirely at leisure take a traditional dugout canoe to explore the lake\\u2019s 29 islands or visit a local community. Following a late afternoon tea, we will begin the drive toward Lake Mburo National Park. Arriving in the evening, you\'ll check into your lodge for dinner, ready to wake up already inside the park the next morning.\"}]', NULL, NULL, NULL, '2026-03-28 21:24:48', '2026-03-28 21:24:48'),
(57, 9, 14, 'Today is dedicated to experiencing the unique acacia woodlands of Lake Mburo. After breakfast, you’ll enjoy an extensive morning game drive to see zebras, impalas, and giraffes. Following a long lunch and a siesta, you will take a sunset boat cruise on the lake to spot hippos and the rare African Finfoot. This slow pace ensures you truly connect with the park\'s peaceful atmosphere', 'Full Day in Lake Mburo National Park', '', NULL, 'breakfast, lunch, Dinner', '[{\"id\":\"blk-c4df02a0-ef0e-4b95-a400-e141c01df913\",\"type\":\"text\",\"text\":\"Today is dedicated to experiencing the unique acacia woodlands of Lake Mburo. After breakfast, you\\u2019ll enjoy an extensive morning game drive to see zebras, impalas, and giraffes. Following a long lunch and a siesta, you will take a sunset boat cruise on the lake to spot hippos and the rare African Finfoot. This slow pace ensures you truly connect with the park\'s peaceful atmosphere\"}]', NULL, NULL, NULL, '2026-03-28 21:24:48', '2026-03-28 21:24:48'),
(58, 9, 15, 'For your final morning, trade the vehicle for your hiking boots and take a guided walking safari after breakfast. You’ll experience the thrill of walking among wildlife on foot. Afterward, we begin our return journey, stopping at the Equator for photos and lunch. Your guide will transfer you to Entebbe Airport for your evening flight, concluding your 15-day adventure', 'Walking Safari & The Equator Crossing', '', NULL, 'Breakfast  and lunch', '[{\"id\":\"blk-7abb25fa-aac0-4b17-8198-bea12a9872f9\",\"type\":\"text\",\"text\":\"For your final morning, trade the vehicle for your hiking boots and take a guided walking safari after breakfast. You\\u2019ll experience the thrill of walking among wildlife on foot. Afterward, we begin our return journey, stopping at the Equator for photos and lunch. Your guide will transfer you to Entebbe Airport for your evening flight, concluding your 15-day adventure\"}]', NULL, NULL, NULL, '2026-03-28 21:24:48', '2026-03-28 21:24:48'),
(59, 1, 1, 'Your adventure begins with an early morning departure from Kampala, heading west through scenic countryside dotted with rolling hills, tea plantations, and traditional homesteads.\r\n\r\nEnjoy a stopover at the Equator for photos and another in Mbarara for lunch. Continue the journey to Bwindi Impenetrable National Park, a UNESCO World Heritage Site known for its rich biodiversity. Arrive in the evening, check in at your lodge, and relax as you prepare for the next day’s unforgettable encounter.', 'Transfer from Kampala to Bwindi Impenetrable Forest', '', NULL, 'lunch, dinner', '[{\"id\":\"blk-490b79e9-0486-47e8-98ac-dd9c949a1857\",\"type\":\"text\",\"text\":\"Your adventure begins with an early morning departure from Kampala, heading west through scenic countryside dotted with rolling hills, tea plantations, and traditional homesteads.\\n\\nEnjoy a stopover at the Equator for photos and another in Mbarara for lunch. Continue the journey to Bwindi Impenetrable National Park, a UNESCO World Heritage Site known for its rich biodiversity. Arrive in the evening, check in at your lodge, and relax as you prepare for the next day\\u2019s unforgettable encounter.\"}]', NULL, NULL, NULL, '2026-04-03 14:59:14', '2026-04-03 14:59:14'),
(60, 1, 2, 'After an early breakfast, head to the park headquarters for a briefing before entering the dense forest for gorilla trekking. This once-in-a-lifetime experience brings you face-to-face with endangered mountain gorillas in their natural habitat an emotional and thrilling wildlife encounter.\r\n\r\nAfter the trek, return to the lodge for refreshment and then transfer to the breathtaking Lake Bunyonyi, often referred to as the “Switzerland of Africa” due to its scenic beauty. Arrive in the evening, check in, and unwind with stunning lake views.', 'Gorilla Trekking & Transfer to Lake Bunyonyi', '', NULL, 'Breakfast, Lunch, Dinner', '[{\"id\":\"blk-aebf839e-7c3d-4598-afe4-0c560f027532\",\"type\":\"text\",\"text\":\"After an early breakfast, head to the park headquarters for a briefing before entering the dense forest for gorilla trekking. This once-in-a-lifetime experience brings you face-to-face with endangered mountain gorillas in their natural habitat an emotional and thrilling wildlife encounter.\\n\\nAfter the trek, return to the lodge for refreshment and then transfer to the breathtaking Lake Bunyonyi, often referred to as the \\u201cSwitzerland of Africa\\u201d due to its scenic beauty. Arrive in the evening, check in, and unwind with stunning lake views.\"}]', NULL, NULL, NULL, '2026-04-03 14:59:14', '2026-04-03 14:59:14'),
(61, 1, 3, 'Wake up to a peaceful morning by Lake Bunyonyi. Enjoy optional activities such as canoeing, bird watching, or simply relaxing by the lakeside surrounded by terraced hills and fresh air.\r\n\r\nLater, begin your return journey to Kampala with lunch en route, arriving in the evening marking the end of your unforgettable gorilla trekking safari.', 'Relaxation at Lake Bunyonyi & Return to Kampala', '', NULL, 'Breakfast, Lunch and Dinner', '[{\"id\":\"blk-83dfb790-63c7-4280-b967-601dfc03726e\",\"type\":\"text\",\"text\":\"Wake up to a peaceful morning by Lake Bunyonyi. Enjoy optional activities such as canoeing, bird watching, or simply relaxing by the lakeside surrounded by terraced hills and fresh air.\\n\\nLater, begin your return journey to Kampala with lunch en route, arriving in the evening marking the end of your unforgettable gorilla trekking safari.\"}]', NULL, NULL, NULL, '2026-04-03 14:59:14', '2026-04-03 14:59:14'),
(62, 10, 1, 'Your African adventure begins the moment you land at Entebbe International Airport. Our professional driver-guide will be waiting for you in the arrivals hall, holding a sign with your name, ready to transfer you smoothly to your hotel.\r\n\r\nEntebbe is a charming lakeside town nestled on the shores of Lake Victoria Africa\'s largest lake. After the long journey, today is all about settling in, refreshing, and preparing your spirit for the extraordinary days ahead.\r\n\r\nIn the evening, your guide will conduct a comprehensive safari briefing walking you through the itinerary, what to pack for each activity, health and safety tips, and answering all your questions. A welcome dinner awaits you at your lodge, where you\'ll enjoy your first taste of Ugandan hospitality.', 'Arrival in Entebbe-Welcome to the Pearl of Africa', '', NULL, 'Dinner', '[{\"id\":\"blk-b97a883b-8b7e-44c3-a1dd-fbdc0c40a641\",\"type\":\"text\",\"text\":\"Your African adventure begins the moment you land at Entebbe International Airport. Our professional driver-guide will be waiting for you in the arrivals hall, holding a sign with your name, ready to transfer you smoothly to your hotel.\\n\\nEntebbe is a charming lakeside town nestled on the shores of Lake Victoria Africa\'s largest lake. After the long journey, today is all about settling in, refreshing, and preparing your spirit for the extraordinary days ahead.\\n\\nIn the evening, your guide will conduct a comprehensive safari briefing walking you through the itinerary, what to pack for each activity, health and safety tips, and answering all your questions. A welcome dinner awaits you at your lodge, where you\'ll enjoy your first taste of Ugandan hospitality.\"}]', NULL, NULL, NULL, '2026-04-06 23:56:13', '2026-04-07 00:01:05'),
(63, 10, 2, 'After an early breakfast, we embark northward on one of Uganda\'s most rewarding road journeys. Your first stop is the Ziwa Rhino Sanctuary  the only place in Uganda where you can encounter the magnificent Southern White Rhinoceros in the wild.\r\n\r\nLed by experienced rangers, you\'ll trek on foot through the sanctuary\'s savannah grasslands, getting remarkably close to these gentle giants. It is a rare, intimate wildlife encounter that most safari-goers never get to experience. Your guide will share fascinating facts about the ongoing conservation efforts to restore rhinos to Uganda\'s national parks.\r\n\r\nAfter lunch at the sanctuary, we continue our drive through rolling countryside and Ugandan village life, crossing the Karuma Bridge over the mighty River Nile, before arriving at your lodge inside Murchison Falls National Park  Uganda\'s largest and oldest protected area  in time for a sundowner and dinner.', 'Entebbe to Ziwa Rhino Sanctuary-Then Onward to Murchison Falls', '', NULL, 'Breakfast, Lunch, Dinner', '[{\"id\":\"blk-30a5fbc1-3f2a-4c22-8388-0f73eefcd679\",\"type\":\"text\",\"text\":\"After an early breakfast, we embark northward on one of Uganda\'s most rewarding road journeys. Your first stop is the Ziwa Rhino Sanctuary \\u2014 the only place in Uganda where you can encounter the magnificent Southern White Rhinoceros in the wild.\\n\\nLed by experienced rangers, you\'ll trek on foot through the sanctuary\'s savannah grasslands, getting remarkably close to these gentle giants. It is a rare, intimate wildlife encounter that most safari-goers never get to experience. Your guide will share fascinating facts about the ongoing conservation efforts to restore rhinos to Uganda\'s national parks.\\n\\nAfter lunch at the sanctuary, we continue our drive through rolling countryside and Ugandan village life, crossing the Karuma Bridge over the mighty River Nile, before arriving at your lodge inside Murchison Falls National Park  Uganda\'s largest and oldest protected area \\u2014 in time for a sundowner and dinner.\"}]', NULL, NULL, NULL, '2026-04-06 23:56:13', '2026-04-08 19:51:06'),
(64, 10, 3, 'Today is a full, exhilarating day in Murchison Falls National Park  home to some of the largest wildlife populations in East Africa. We begin with an early morning game drive on the northern bank of the River Nile, where the golden sunrise illuminates vast savannah plains teeming with life.\r\n\r\nExpect sightings of elephants, lions, leopards, buffaloes, giraffes, Uganda kob, oribi, hartebeest, and a spectacular variety of birds including the rare Shoebill Stork. Your experienced guide knows every corner of this park, and will ensure you are perfectly positioned for the best wildlife encounters.\r\n\r\nIn the afternoon, board a private launch for the Nile River boat cruise  a breathtaking journey upstream toward the thunderous Murchison Falls, where the entire River Nile is compressed through a seven-metre gorge in one of nature\'s most dramatic spectacles. Along the Nile\'s banks you\'ll see hippo pods, Nile crocodiles, elephants drinking, and hundreds of waterbirds in their natural habitat. This is one of Uganda\'s most iconic safari experiences.', 'Murchison Falls-Game Drive & Boat Cruise to the Falls', '', NULL, 'Breakfast, Lunch and Dinner', '[{\"id\":\"blk-3f0935a4-2fce-4db0-a816-7a307e8cd615\",\"type\":\"text\",\"text\":\"Today is a full, exhilarating day in Murchison Falls National Park  home to some of the largest wildlife populations in East Africa. We begin with an early morning game drive on the northern bank of the River Nile, where the golden sunrise illuminates vast savannah plains teeming with life.\\n\\nExpect sightings of elephants, lions, leopards, buffaloes, giraffes, Uganda kob, oribi, hartebeest, and a spectacular variety of birds including the rare Shoebill Stork. Your experienced guide knows every corner of this park, and will ensure you are perfectly positioned for the best wildlife encounters.\\n\\nIn the afternoon, board a private launch for the Nile River boat cruise  a breathtaking journey upstream toward the thunderous Murchison Falls, where the entire River Nile is compressed through a seven-metre gorge in one of nature\'s most dramatic spectacles. Along the Nile\'s banks you\'ll see hippo pods, Nile crocodiles, elephants drinking, and hundreds of waterbirds in their natural habitat. This is one of Uganda\'s most iconic safari experiences.\"}]', NULL, NULL, NULL, '2026-04-07 00:01:05', '2026-04-07 00:01:05'),
(65, 10, 4, 'We begin with a final morning game drive on the southern bank of Murchison Falls  a different landscape from yesterday, with dense woodland and thicket providing habitat for different species including chimpanzees, red-tailed monkeys, and a remarkable variety of forest birds.\r\n\r\nAfter a leisurely lunch, we set off southward through Uganda\'s green, hilly heartland. The drive itself is a scenic delight  passing through fertile farmlands, banana plantations, local trading centres, and the magnificent Albertine Rift Valley escarpment with views that stretch for miles.\r\n\r\nEn route, we stop at the famous Equator monument at Kayabwe a fun and memorable stop where you can stand with one foot in each hemisphere and witness the fascinating Coriolis effect experiment performed by local guides. We arrive at our lodge in Queen Elizabeth National Park in time for dinner, refreshed and full of anticipation for tomorrow.', 'Murchison Falls to Queen Elizabeth National Park', '', NULL, 'Breakfast, Lunch and Dinner', '[{\"id\":\"blk-e6e5ac89-6f32-4f7c-832e-e883656d0156\",\"type\":\"text\",\"text\":\"We begin with a final morning game drive on the southern bank of Murchison Falls  a different landscape from yesterday, with dense woodland and thicket providing habitat for different species including chimpanzees, red-tailed monkeys, and a remarkable variety of forest birds.\\n\\nAfter a leisurely lunch, we set off southward through Uganda\'s green, hilly heartland. The drive itself is a scenic delight  passing through fertile farmlands, banana plantations, local trading centres, and the magnificent Albertine Rift Valley escarpment with views that stretch for miles.\\n\\nEn route, we stop at the famous Equator monument at Kayabwe a fun and memorable stop where you can stand with one foot in each hemisphere and witness the fascinating Coriolis effect experiment performed by local guides. We arrive at our lodge in Queen Elizabeth National Park in time for dinner, refreshed and full of anticipation for tomorrow.\"}]', NULL, NULL, NULL, '2026-04-07 00:01:05', '2026-04-07 00:01:05'),
(66, 10, 5, 'A thrilling full day in Queen Elizabeth National Park  one of Africa\'s most biodiverse protected areas, home to over 95 mammal species and more than 600 bird species. We start with an early game drive through the Kasenyi Plains, the finest lion territory in the park.\r\n\r\nThe Kasenyi area is famous for lion prides, herds of elephant, buffalo, and Uganda kob  the national animal. With luck, you may also witness the extraordinary spectacle of a lion hunt or spot the elusive leopard resting in a fig tree. The open savannah makes for excellent visibility and outstanding photography.\r\n\r\nIn the afternoon, we board a launch for the celebrated Kazinga Channel boat cruise  a 32-kilometre natural channel linking Lakes George and Edward. The channel\'s shores host the largest concentration of hippos in Africa, and you\'ll drift peacefully alongside elephants drinking at the water\'s edge, enormous crocodiles basking in the sun, and an extraordinary tapestry of waterbirds including pelicans, cormorants, kingfishers, and African fish eagles. This is quintessential Uganda safari at its very finest.', 'Queen Elizabeth  Game Drive & Kazinga Channel Cruise', '', NULL, '', '[{\"id\":\"blk-dfedd5eb-e6c1-4241-9514-d427a92c0a9a\",\"type\":\"text\",\"text\":\"A thrilling full day in Queen Elizabeth National Park  one of Africa\'s most biodiverse protected areas, home to over 95 mammal species and more than 600 bird species. We start with an early game drive through the Kasenyi Plains, the finest lion territory in the park.\\n\\nThe Kasenyi area is famous for lion prides, herds of elephant, buffalo, and Uganda kob  the national animal. With luck, you may also witness the extraordinary spectacle of a lion hunt or spot the elusive leopard resting in a fig tree. The open savannah makes for excellent visibility and outstanding photography.\\n\\nIn the afternoon, we board a launch for the celebrated Kazinga Channel boat cruise  a 32-kilometre natural channel linking Lakes George and Edward. The channel\'s shores host the largest concentration of hippos in Africa, and you\'ll drift peacefully alongside elephants drinking at the water\'s edge, enormous crocodiles basking in the sun, and an extraordinary tapestry of waterbirds including pelicans, cormorants, kingfishers, and African fish eagles. This is quintessential Uganda safari at its very finest.\"}]', NULL, NULL, NULL, '2026-04-07 00:01:05', '2026-04-07 00:01:05'),
(67, 10, 6, 'Today\'s journey takes you from the open savannah into one of Africa\'s most ancient and awe-inspiring ecosystems. We depart after breakfast and drive through the Ishasha sector of Queen Elizabeth National Park  world-famous for its tree-climbing lions, a remarkable phenomenon found in very few places on earth. Keep your camera ready as you scan the broad fig trees for these extraordinary cats lounging in the canopy.\r\n\r\nFrom Ishasha, we wind through the stunning Kigezi Highlands  a landscape of terraced hillsides, crater lakes, and traditional homesteads that earned this region the name \"Switzerland of Africa.\" The scenery is breathtaking at every turn.\r\n\r\nUpon arrival at your lodge on the edge of Bwindi Impenetrable National Park, take time to absorb the atmosphere of one of the world\'s most sacred natural places  a UNESCO World Heritage Site and one of Africa\'s oldest rainforests, home to nearly half of all remaining mountain gorillas on earth. In the evening, your guide and the park rangers will give you a thorough gorilla trekking briefing  covering regulations, what to expect, and how to make the most of your once-in-a-lifetime encounter tomorrow', 'Queen Elizabeth to Bwindi Impenetrable Forest', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-cf7724df-edea-4a7a-9032-2538aa26332c\",\"type\":\"text\",\"text\":\"Today\'s journey takes you from the open savannah into one of Africa\'s most ancient and awe-inspiring ecosystems. We depart after breakfast and drive through the Ishasha sector of Queen Elizabeth National Park  world-famous for its tree-climbing lions, a remarkable phenomenon found in very few places on earth. Keep your camera ready as you scan the broad fig trees for these extraordinary cats lounging in the canopy.\\n\\nFrom Ishasha, we wind through the stunning Kigezi Highlands  a landscape of terraced hillsides, crater lakes, and traditional homesteads that earned this region the name \\\"Switzerland of Africa.\\\" The scenery is breathtaking at every turn.\\n\\nUpon arrival at your lodge on the edge of Bwindi Impenetrable National Park, take time to absorb the atmosphere of one of the world\'s most sacred natural places  a UNESCO World Heritage Site and one of Africa\'s oldest rainforests, home to nearly half of all remaining mountain gorillas on earth. In the evening, your guide and the park rangers will give you a thorough gorilla trekking briefing  covering regulations, what to expect, and how to make the most of your once-in-a-lifetime encounter tomorrow\"}]', NULL, NULL, NULL, '2026-04-07 00:01:05', '2026-04-07 00:01:05'),
(68, 10, 7, 'This is the day that defines the entire journey  your mountain gorilla trekking experience in Bwindi Impenetrable National Park. Rise early for a hearty breakfast, then make your way to the park headquarters where your ranger guides will assign you to a gorilla family group.\r\n\r\nThe trek itself is an adventure  navigating steep, dense forest trails through ancient vegetation, guided by expert trackers who follow the gorillas\' movements with remarkable skill. The terrain can be challenging, but every step is worth it. When your guide raises a hand and whispers \"they are here,\" and you part the undergrowth to find yourself just metres away from a family of mountain gorillas going about their daily lives  mothers nursing infants, silverbacks beating their chests, juveniles wrestling and tumbling  the world stops completely.\r\n\r\nYou spend one precious hour with the gorilla family  a sacred, humbling encounter that every guest describes as the single most profound wildlife experience of their lives. This is the true highlight of your Uganda safari. After the trek, we drive to the enchanting Lake Bunyonyi arriving in time for a well-deserved dinner with views over the lake\'s shimmering islands.', 'Gorilla Trekking in Bwindi-Then Lake Bunyonyi', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-9dfb820d-35fa-4d7f-8858-f41425293efe\",\"type\":\"text\",\"text\":\"This is the day that defines the entire journey  your mountain gorilla trekking experience in Bwindi Impenetrable National Park. Rise early for a hearty breakfast, then make your way to the park headquarters where your ranger guides will assign you to a gorilla family group.\\n\\nThe trek itself is an adventure  navigating steep, dense forest trails through ancient vegetation, guided by expert trackers who follow the gorillas\' movements with remarkable skill. The terrain can be challenging, but every step is worth it. When your guide raises a hand and whispers \\\"they are here,\\\" and you part the undergrowth to find yourself just metres away from a family of mountain gorillas going about their daily lives  mothers nursing infants, silverbacks beating their chests, juveniles wrestling and tumbling  the world stops completely.\\n\\nYou spend one precious hour with the gorilla family  a sacred, humbling encounter that every guest describes as the single most profound wildlife experience of their lives. This is the true highlight of your Uganda safari. After the trek, we drive to the enchanting Lake Bunyonyi arriving in time for a well-deserved dinner with views over the lake\'s shimmering islands.\"}]', NULL, NULL, NULL, '2026-04-07 00:07:30', '2026-04-07 00:07:30'),
(69, 10, 8, 'After the physical and emotional intensity of gorilla trekking, today is a beautifully balanced day of relaxation and gentle exploration at Lake Bunyonyi  Uganda\'s deepest lake and one of the most serene destinations on the continent. Bunyonyi translates to \"place of many little birds,\" and as you wake to the sound of birdsong over still water, you\'ll understand why.\r\n\r\nThe lake is scattered with 29 islands, each with its own fascinating history and story. This morning, take a traditional dugout canoe ride across the calm waters  gliding between islands, watching local fishermen at work, and enjoying the extraordinary panorama of terraced green hillsides reflecting in the lake. Your guide will bring the islands\' histories to life, including the sobering story of Punishment Island, where unmarried pregnant girls were once abandoned  a powerful reminder of how far Ugandan society has evolved.\r\n\r\nThe afternoon is entirely yours  swim in the lake\'s safe, bilharzia-free waters, stroll through a nearby Bakiga village for a cultural interaction, or simply sit on your lodge terrace with a cold drink watching the world float gently by. As the sun sets behind the Kigezi hills, casting golden reflections across the water, you\'ll understand why travellers describe Lake Bunyonyi as one of Africa\'s most magical places.', 'Lake Bunyonyi  A Day of Peace & Wonder', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-44cf54bd-2197-4dea-9323-1e475f54b8da\",\"type\":\"text\",\"text\":\"After the physical and emotional intensity of gorilla trekking, today is a beautifully balanced day of relaxation and gentle exploration at Lake Bunyonyi  Uganda\'s deepest lake and one of the most serene destinations on the continent. Bunyonyi translates to \\\"place of many little birds,\\\" and as you wake to the sound of birdsong over still water, you\'ll understand why.\\n\\nThe lake is scattered with 29 islands, each with its own fascinating history and story. This morning, take a traditional dugout canoe ride across the calm waters  gliding between islands, watching local fishermen at work, and enjoying the extraordinary panorama of terraced green hillsides reflecting in the lake. Your guide will bring the islands\' histories to life, including the sobering story of Punishment Island, where unmarried pregnant girls were once abandoned  a powerful reminder of how far Ugandan society has evolved.\\n\\nThe afternoon is entirely yours  swim in the lake\'s safe, bilharzia-free waters, stroll through a nearby Bakiga village for a cultural interaction, or simply sit on your lodge terrace with a cold drink watching the world float gently by. As the sun sets behind the Kigezi hills, casting golden reflections across the water, you\'ll understand why travellers describe Lake Bunyonyi as one of Africa\'s most magical places.\"}]', NULL, NULL, NULL, '2026-04-07 00:07:30', '2026-04-07 00:07:30'),
(70, 10, 9, 'After a relaxed breakfast overlooking the still waters of Lake Bunyonyi, we pack up and begin our scenic drive eastward toward Lake Mburo National Park a journey of approximately 4.5 to 5 hours through some of Uganda\'s most beautiful countryside.\r\n\r\nThe road winds through the Kigezi highlands, dropping gradually from the misty hills of the southwest into the warmer, drier pastoral lands of western Uganda. As you pass through Mbarara  Uganda\'s second largest city he landscape opens into sweeping savannah plains dotted with the iconic long-horned Ankole cattle, proudly herded by the Bahima pastoralists who have called this land home for centuries. Your guide will share the rich cultural significance of these magnificent animals, whose horns can span over a metre wide.\r\n\r\nWe arrive at Lake Mburo National Park in the early afternoon, in time for lunch at your lodge and a chance to freshen up after the road. As the afternoon light softens into that warm golden hour that Africa does so perfectly, we head out for a late afternoon game drive through the park\'s varied acacia woodland and open grassy valleys.\r\n\r\nLake Mburo is an intimate, unhurried park  and that is precisely its charm. Unlike Uganda\'s larger parks, here the wildlife feels close and personal. Look out for zebras grazing in the open plains, impalas leaping through the bush, warthogs trotting with their tails raised, elands, topi, oribi, and buffaloes gathering at the waterhole as evening approaches. With patience and a good guide, the elusive leopard and hyena may also make an appearance in the fading light. Return to your lodge for dinner under a sky full of stars  a perfect, unhurried end to a long and beautiful travel day.', 'Lake Bunyonyi to Lake Mburo National Park', '', NULL, 'breakfast, lunch and Dinner', '[{\"id\":\"blk-7cc28459-3621-4189-b529-525aac7a0be2\",\"type\":\"text\",\"text\":\"After a relaxed breakfast overlooking the still waters of Lake Bunyonyi, we pack up and begin our scenic drive eastward toward Lake Mburo National Park a journey of approximately 4.5 to 5 hours through some of Uganda\'s most beautiful countryside.\\n\\nThe road winds through the Kigezi highlands, dropping gradually from the misty hills of the southwest into the warmer, drier pastoral lands of western Uganda. As you pass through Mbarara  Uganda\'s second largest city he landscape opens into sweeping savannah plains dotted with the iconic long-horned Ankole cattle, proudly herded by the Bahima pastoralists who have called this land home for centuries. Your guide will share the rich cultural significance of these magnificent animals, whose horns can span over a metre wide.\\n\\nWe arrive at Lake Mburo National Park in the early afternoon, in time for lunch at your lodge and a chance to freshen up after the road. As the afternoon light softens into that warm golden hour that Africa does so perfectly, we head out for a late afternoon game drive through the park\'s varied acacia woodland and open grassy valleys.\\n\\nLake Mburo is an intimate, unhurried park  and that is precisely its charm. Unlike Uganda\'s larger parks, here the wildlife feels close and personal. Look out for zebras grazing in the open plains, impalas leaping through the bush, warthogs trotting with their tails raised, elands, topi, oribi, and buffaloes gathering at the waterhole as evening approaches. With patience and a good guide, the elusive leopard and hyena may also make an appearance in the fading light. Return to your lodge for dinner under a sky full of stars  a perfect, unhurried end to a long and beautiful travel day.\"}]', NULL, NULL, NULL, '2026-04-07 00:07:30', '2026-04-07 00:07:30'),
(71, 10, 10, 'Your final morning in the African wild  savour every moment. Rise early for one last game walk or game drive in Lake Mburo National Park before the long journey home. A guided nature walk with an armed ranger guide is particularly rewarding here, allowing you to track wildlife on foot, learn about medicinal plants, and hear the park in a way no vehicle safari can offer. The dawn chorus of birds at Lake Mburo is nothing short of magical.\r\n\r\nAfter a leisurely breakfast and checkout, we begin the drive back toward Entebbe  approximately 4 to 5 hours. Along the way, stop one final time at the Equator monument if you haven\'t yet had the chance, pick up last-minute crafts and souvenirs from local artisans, and soak in the Ugandan countryside one last time.\r\n\r\nAs you arrive at Entebbe for your flight home, you carry with you something no photograph can fully capture  the memory of a silverback gorilla\'s gaze, the thunder of Murchison Falls, the silence of a Lake Bunyonyi sunset, and the quiet dignity of Africa\'s greatest wildlife. Uganda does not just visit you  it stays with you.', 'Lake Mburo Morning Safari -Return to Entebbe', '', NULL, 'breakfast  and lunch (Dinner where if possible)', '[{\"id\":\"blk-d69617d3-fc62-43e1-a3d7-94be34f7da42\",\"type\":\"text\",\"text\":\"Your final morning in the African wild  savour every moment. Rise early for one last game walk or game drive in Lake Mburo National Park before the long journey home. A guided nature walk with an armed ranger guide is particularly rewarding here, allowing you to track wildlife on foot, learn about medicinal plants, and hear the park in a way no vehicle safari can offer. The dawn chorus of birds at Lake Mburo is nothing short of magical.\\n\\nAfter a leisurely breakfast and checkout, we begin the drive back toward Entebbe  approximately 4 to 5 hours. Along the way, stop one final time at the Equator monument if you haven\'t yet had the chance, pick up last-minute crafts and souvenirs from local artisans, and soak in the Ugandan countryside one last time.\\n\\nAs you arrive at Entebbe for your flight home, you carry with you something no photograph can fully capture  the memory of a silverback gorilla\'s gaze, the thunder of Murchison Falls, the silence of a Lake Bunyonyi sunset, and the quiet dignity of Africa\'s greatest wildlife. Uganda does not just visit you  it stays with you.\"}]', NULL, NULL, NULL, '2026-04-07 00:09:13', '2026-04-07 00:09:13');

